import { GoogleGenAI, Type } from "@google/genai";
import { GeminiAdvice, ChatMessage } from "../types";

/**
 * World-class Gemini Service for A/L 2026 Portal
 * Uses Gemini 3 Pro for complex academic reasoning and 3 Flash for speed/search.
 */

export const getDailyAdvice = async (daysRemaining: number): Promise<GeminiAdvice> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: `Candidate has ${daysRemaining} days for Sri Lanka GCE A/L 2026. Provide short, practical, and highly motivating study advice. Keep it under 30 words.` }] }],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            category: { 
              type: Type.STRING,
              enum: ['motivation', 'study-tip', 'exam-strategy']
            }
          },
          required: ["title", "content", "category"]
        }
      },
    });

    const text = response.text?.trim();
    return text ? JSON.parse(text) : { title: "Stay Focused", content: "Your consistency today determines your results in 2026.", category: "motivation" };
  } catch (error: any) {
    console.error("Advice Error:", error);
    return { title: "Resilience", content: "Consistency beats intensity. Keep moving forward.", category: "motivation" };
  }
};

export const chatWithStudyBuddy = async (history: ChatMessage[], prompt: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const chat = ai.chats.create({
      model: "gemini-3-pro-preview", // Upgraded to Pro for complex STEM/Academic tasks
      config: {
        systemInstruction: "You are 'A-Level Buddy', a world-class senior academic consultant for Sri Lankan A/L students (2026 Batch). You specialize in Math, Physics, Chemistry, and ICT. Help with complex concepts, study schedules, and exam pressure. Use local context like 'Tuition classes', 'Past Papers', 'Z-Score', and 'doenets.lk'. Keep responses concise, encouraging, and highly professional.",
      }
    });

    // Note: sendMessage only accepts 'message', not 'contents'
    const result = await chat.sendMessage({ message: prompt });
    return result.text || "I'm here to help, but I missed that last thought. Could you rephrase?";
  } catch (error: any) {
    console.error("Chat Error:", error);
    if (error.message?.includes("Requested entity was not found")) {
      return "I'm having trouble accessing my advanced reasoning core. This usually happens if the project configuration is still propagating. Please try again in a moment.";
    }
    return "I'm temporarily disconnected from my knowledge base. Please check your connection.";
  }
};

export interface ExamNews {
  text: string;
  sources: { uri: string; title: string }[];
  isConfirmed: boolean;
  error?: string;
}

export const fetchLatestExamNews = async (): Promise<ExamNews> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [{ parts: [{ text: "Search for latest official news and updates regarding the Sri Lanka GCE A/L 2026 examination schedule, registration dates, and Department of Examinations (doenets.lk) announcements." }] }],
      config: {
        tools: [{ googleSearch: {} }],
      },
    });

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((chunk: any) => ({
        uri: chunk.web?.uri,
        title: chunk.web?.title
      }))
      .filter((s: any) => s.uri && s.title) || [];

    const text = response.text || "Scanning official portals for 2026 updates...";
    const isConfirmed = text.toLowerCase().includes("official") || text.includes("2026");

    return {
      text: text,
      sources: sources.slice(0, 4),
      isConfirmed
    };
  } catch (error: any) {
    console.error("News Fetch Error:", error);
    return {
      text: "Currently monitoring official channels. Check doenets.lk for the most immediate updates.",
      sources: [{ uri: "https://www.doenets.lk", title: "Official Department of Examinations Portal" }],
      isConfirmed: false
    };
  }
};

import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig(({ mode }) => {
  // Load environment variables based on the current mode (development/production)
  // This ensures Vercel's API_KEY is available during the build process
  const env = loadEnv(mode, process.cwd(), '');

  return {
    plugins: [react()],
    define: {
      // Replaces 'process.env.API_KEY' in the code with the actual key value at build time.
      // This is essential for Vite as it does not provide process.env to the browser by default.
      'process.env.API_KEY': JSON.stringify(env.API_KEY || '')
    },
    server: {
      port: 3000,
      open: true
    },
    build: {
      outDir: 'dist',
      sourcemap: true,
      rollupOptions: {
        output: {
          manualChunks: {
            vendor: ['react', 'react-dom'],
            genai: ['@google/genai']
          }
        }
      }
    }
  };
});

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithStudyBuddy } from '../services/geminiService';

const AIChatBuddy: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (error) {
      const timer = setTimeout(() => setError(null), 8000);
      return () => clearTimeout(timer);
    }
  }, [error]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setError(null);

    try {
      const response = await chatWithStudyBuddy([...messages, userMsg], currentInput);
      const botMsg: ChatMessage = { role: 'model', text: response, timestamp: Date.now() };
      setMessages(prev => [...prev, botMsg]);
    } catch (err: any) {
      setError("AI Service busy. This can happen during peak hours or if the API key is misconfigured on Vercel.");
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="glass-card rounded-[2.5rem] p-6 md:p-8 border-indigo-500/10 flex flex-col h-[calc(100vh-280px)] min-h-[550px] relative shadow-2xl">
      {/* Background Glow */}
      <div className="absolute inset-0 bg-indigo-600/5 pointer-events-none rounded-[2.5rem]" />

      {error && (
        <div className="absolute top-4 left-4 right-4 z-50 animate-reveal">
          <div className="bg-red-500/10 backdrop-blur-xl border border-red-500/30 rounded-2xl p-4 flex items-center justify-between shadow-2xl">
            <div className="flex items-center gap-3">
              <span className="text-red-400">⚠️</span>
              <span className="text-xs font-bold text-red-200">{error}</span>
            </div>
            <button onClick={() => setError(null)} className="text-red-400 hover:text-white">✕</button>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between mb-6 shrink-0">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-2xl bg-indigo-600 flex items-center justify-center text-white shadow-lg shadow-indigo-900/40">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM7 9a1 1 0 100-2 1 1 0 000 2zm7-1a1 1 0 11-2 0 1 1 0 012 0zm-7.535 5.503a1 1 0 10-1.415 1.414 3 3 0 004.242 0 1 1 0 00-1.415-1.414 1 1 0 01-1.412 0z" clipRule="evenodd" />
            </svg>
          </div>
          <div>
            <h3 className="font-black text-sm uppercase tracking-widest text-white leading-none">A/L Study Buddy</h3>
            <span className="text-[10px] text-indigo-400 font-bold uppercase tracking-tighter">Gemini 3 Pro Intelligence</span>
          </div>
        </div>
        <div className="flex items-center gap-2">
           <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">Status:</span>
           <div className={`w-2 h-2 rounded-full ${isTyping ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'} shadow-lg`} />
        </div>
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto pr-2 custom-scrollbar space-y-6 mb-6">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-6">
            <div className="w-20 h-20 bg-indigo-500/5 rounded-full flex items-center justify-center text-4xl mb-6 border border-indigo-500/10">🎓</div>
            <h4 className="text-white font-bold mb-2">Academic Support Active</h4>
            <p className="text-slate-500 text-xs leading-relaxed max-w-xs">Ask me about Pure Maths integration, Physics mechanics, or Chemistry reaction mechanisms.</p>
            <div className="grid grid-cols-1 gap-2 mt-8 w-full max-w-xs">
              {['"Explain the laws of friction"', '"Help me with a study plan"', '"How to solve quadratic equations"'].map(prompt => (
                <button 
                  key={prompt}
                  onClick={() => setInput(prompt.replace(/"/g, ''))}
                  className="p-3 text-[10px] font-bold text-slate-400 bg-slate-900/50 border border-white/5 rounded-xl hover:bg-indigo-600 hover:text-white hover:border-indigo-500 transition-all text-left"
                >
                  {prompt}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-reveal`}>
            <div className={`max-w-[88%] p-4 rounded-[1.5rem] text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-gradient-to-br from-indigo-600 to-blue-700 text-white rounded-tr-none' 
                : 'bg-slate-900/90 text-slate-200 border border-white/5 rounded-tl-none font-medium'
            }`}>
              {msg.text}
              <div className={`text-[8px] mt-2 font-bold opacity-40 ${msg.role === 'user' ? 'text-right' : 'text-left'}`}>
                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </div>
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-reveal">
            <div className="bg-slate-900/90 p-5 rounded-[1.5rem] rounded-tl-none flex gap-1.5 items-center border border-white/5">
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '200ms' }} />
              <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce" style={{ animationDelay: '400ms' }} />
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-2">Buddy Thinking...</span>
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="relative mt-auto">
        <div className="absolute -top-4 left-4 right-4 h-px bg-gradient-to-r from-transparent via-white/5 to-transparent" />
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Type your academic query here..."
          className="w-full bg-slate-950/80 border border-white/10 rounded-2xl px-6 py-4 text-sm text-white focus:outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all pr-14 placeholder-slate-600"
        />
        <button 
          type="submit"
          disabled={isTyping || !input.trim()}
          className="absolute right-2.5 top-2.5 bottom-2.5 w-11 h-11 flex items-center justify-center rounded-xl bg-indigo-600 text-white hover:bg-indigo-500 transition-all disabled:opacity-30 active:scale-95 shadow-lg shadow-indigo-900/20"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
            <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default AIChatBuddy;

