import React from 'react';
import { TimeLeft } from '../types';

interface CountdownCardProps {
  timeLeft: TimeLeft;
}

const CountdownCard: React.FC<CountdownCardProps> = ({ timeLeft }) => {
  const Unit: React.FC<{ value: number; label: string; colorClass: string }> = ({ value, label, colorClass }) => {
    const formattedValue = value.toString().padStart(2, '0');

    return (
      <div className="flex flex-col items-center group w-full">
        <div className="countdown-card rounded-[1.5rem] md:rounded-3xl p-3 md:p-6 lg:p-8 w-full transition-all duration-500 hover:translate-y-[-4px] hover:border-blue-400/40 relative flex flex-col items-center justify-center">
          {/* Decorative background circle */}
          <div className={`absolute -right-4 -bottom-4 w-16 h-16 rounded-full blur-2xl opacity-10 group-hover:opacity-20 transition-opacity ${colorClass}`} />

          <div className="flex gap-1 md:gap-2 mb-2 md:mb-4">
            {formattedValue.split('').map((digit, idx) => (
              <div 
                key={idx} 
                className="digit-box rounded-lg md:rounded-2xl w-8 h-12 sm:w-10 sm:h-16 md:w-16 md:h-24 flex items-center justify-center relative overflow-hidden"
              >
                <div className="absolute top-1/2 left-0 w-full h-[1px] bg-white/5 z-10" />
                <span 
                  className="text-xl sm:text-2xl md:text-5xl lg:text-6xl font-black font-mono-tech text-white relative z-0"
                >
                  {digit}
                </span>
              </div>
            ))}
          </div>

          <div className="flex items-center gap-1.5 md:gap-2">
            <div className={`w-1 h-1 md:w-1.5 md:h-1.5 rounded-full ${colorClass} animate-pulse`} />
            <span className="text-[8px] md:text-xs uppercase tracking-[0.2em] text-slate-400 font-bold font-outfit whitespace-nowrap">
              {label}
            </span>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="grid grid-cols-4 gap-2 sm:gap-4 md:gap-6 w-full max-w-5xl mx-auto px-1 sm:px-4">
      <Unit value={timeLeft.days} label="Days" colorClass="bg-blue-500" />
      <Unit value={timeLeft.hours} label="Hours" colorClass="bg-indigo-500" />
      <Unit value={timeLeft.minutes} label="Minutes" colorClass="bg-purple-500" />
      <Unit value={timeLeft.seconds} label="Seconds" colorClass="bg-cyan-500" />
    </div>
  );
};

export default CountdownCard;

import React from 'react';
import { Subject } from '../types';

interface SubjectTrackerProps {
  subjects: Subject[];
  onTogglePriority?: (id: string) => void;
}

const SubjectTracker: React.FC<SubjectTrackerProps> = ({ subjects, onTogglePriority }) => {
  const sortedSubjects = [...subjects].sort((a, b) => {
    if (a.isPrioritized === b.isPrioritized) return 0;
    return a.isPrioritized ? -1 : 1;
  });

  return (
    <div className="glass-card rounded-[2rem] md:rounded-3xl p-5 md:p-8 w-full h-full">
      <h3 className="text-lg md:text-xl font-bold mb-4 md:mb-6 flex items-center gap-2">
        <span className="text-xl md:text-2xl">📈</span> Subject Mastery
      </h3>
      <div className="space-y-4 md:space-y-6">
        {sortedSubjects.map(subject => (
          <div 
            key={subject.id} 
            className={`group p-2.5 md:p-3 rounded-2xl transition-all duration-300 border ${
              subject.isPrioritized 
                ? 'bg-blue-500/5 border-blue-500/20 shadow-[0_0_20px_rgba(59,130,246,0.05)]' 
                : 'border-transparent'
            }`}
          >
            <div className="flex justify-between items-start mb-2">
              <div className="flex items-center gap-2 flex-1 min-w-0">
                {onTogglePriority && (
                  <button 
                    onClick={() => onTogglePriority(subject.id)}
                    className={`shrink-0 transition-colors p-1 -ml-1 ${
                      subject.isPrioritized 
                        ? 'text-amber-400' 
                        : 'text-slate-600 hover:text-slate-400'
                    }`}
                    title={subject.isPrioritized ? "Unprioritize" : "Prioritize this subject"}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor">
                      <path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" />
                    </svg>
                  </button>
                )}
                <div className="flex items-center gap-2 truncate">
                  <span className={`text-xs md:text-sm font-bold truncate ${subject.isPrioritized ? 'text-white' : 'text-slate-400'}`}>
                    {subject.name}
                  </span>
                  {subject.progress >= 80 && (
                    <div className="shrink-0 flex items-center justify-center w-4 h-4 md:w-5 md:h-5 rounded-full bg-emerald-500/20 text-emerald-400 border border-emerald-500/30 animate-pulse">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
                        <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                      </svg>
                    </div>
                  )}
                </div>
              </div>
              <span className={`text-[10px] md:text-xs font-black w-10 text-right shrink-0 ${subject.progress >= 80 ? 'text-emerald-400' : 'text-blue-400'}`}>
                {subject.progress}%
              </span>
            </div>
            <div className="w-full bg-slate-900 rounded-full h-1 md:h-1.5 overflow-hidden border border-slate-800/50">
              <div 
                className={`h-full ${subject.progress >= 80 ? 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]' : subject.color} transition-all duration-700 ease-out`}
                style={{ width: `${subject.progress}%` }}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

