              <section className="text-center mb-6 md:mb-10 lg:mb-12">
                <div className="inline-block mb-3 px-3 py-1 md:px-6 md:py-2 rounded-full bg-blue-500/10 border border-blue-500/20 animate-float shadow-[0_0_20px_rgba(59,130,246,0.1)]">
                  <span className="text-xs md:text-2xl font-black font-outfit text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-yellow-200 to-amber-500 drop-shadow-sm">
