                </div>
              </div>
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
              <StudyGoals />
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8 animate-reveal">
