        );
      case 'credits':
        return (
          <div className="max-w-3xl mx-auto animate-reveal w-full">
            <CreditsPage />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-28 md:pb-32 selection:bg-blue-500/30">
      {/* Dynamic Backgrounds */}
      <div className="fixed top-0 left-0 w-full h-full pointer-events-none overflow-hidden -z-10">
        <div className="absolute top-[-20%] right-[-10%] w-[80%] h-[60%] bg-blue-600/5 blur-[120px] rounded-full animate-float" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[70%] h-[50%] bg-indigo-600/5 blur-[120px] rounded-full animate-float" style={{ animationDelay: '2s' }} />
      </div>

      <nav className="px-4 py-4 md:px-8 md:py-8 flex justify-between items-center max-w-7xl mx-auto sticky top-0 z-[60] backdrop-blur-md bg-slate-950/20">
        <div className="flex items-center gap-2 md:gap-3 cursor-pointer" onClick={() => setActiveView('dashboard')}>
          <div className="w-8 h-8 md:w-10 md:h-10 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-lg flex items-center justify-center font-black text-base md:text-xl shadow-xl shadow-blue-900/40 text-white transform rotate-3">A</div>
          <div className="flex flex-col">
            <span className="text-sm md:text-lg font-black tracking-tighter font-outfit uppercase leading-none text-white">A/L 2026</span>
