import React, { useState, useEffect } from 'react';
import { Subject, TimetableEntry } from '../types';

interface TimetablePageProps {
  subjects: Subject[];
}

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
const HOURS = Array.from({ length: 20 }, (_, i) => `${(i + 4).toString().padStart(2, '0')}:00`);

const TimetablePage: React.FC<TimetablePageProps> = ({ subjects }) => {
  const [entries, setEntries] = useState<TimetableEntry[]>(() => {
    const saved = localStorage.getItem('al_2026_timetable');
    return saved ? JSON.parse(saved) : [];
  });
  const [showModal, setShowModal] = useState(false);
  const [editingEntry, setEditingEntry] = useState<TimetableEntry | null>(null);

  const [formDay, setFormDay] = useState(DAYS[0]);
  const [formStart, setFormStart] = useState('08:00');
  const [formEnd, setFormEnd] = useState('10:00');
  const [formSubjectId, setFormSubjectId] = useState(subjects[0]?.id || '');
  const [formNote, setFormNote] = useState('');

  useEffect(() => {
    localStorage.setItem('al_2026_timetable', JSON.stringify(entries));
  }, [entries]);

  const handleAddClick = () => {
    setEditingEntry(null);
    setShowModal(true);
  };

  const handleEditClick = (entry: TimetableEntry) => {
    setEditingEntry(entry);
    setFormDay(entry.day);
    setFormStart(entry.startTime);
    setFormEnd(entry.endTime);
    setFormSubjectId(entry.subjectId);
    setFormNote(entry.note || '');
    setShowModal(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    const newEntry: TimetableEntry = {
      id: editingEntry?.id || crypto.randomUUID(),
      day: formDay,
      startTime: formStart,
      endTime: formEnd,
      subjectId: formSubjectId,
      note: formNote
    };

    if (editingEntry) {
      setEntries(prev => prev.map(en => en.id === editingEntry.id ? newEntry : en));
    } else {
      setEntries(prev => [...prev, newEntry]);
    }
    setShowModal(false);
    resetForm();
  };

  const resetForm = () => {
    setFormDay(DAYS[0]);
    setFormStart('08:00');
    setFormEnd('10:00');
    setFormSubjectId(subjects[0]?.id || '');
    setFormNote('');
  };

  const handleDelete = (id: string) => {
    setEntries(prev => prev.filter(en => en.id !== id));
    setShowModal(false);
  };

  const getEntryForSlot = (day: string, hour: string) => {
    return entries.filter(en => {
      if (en.day !== day) return false;
      const startHour = parseInt(en.startTime.split(':')[0]);
      const endHour = parseInt(en.endTime.split(':')[0]);
      const slotHour = parseInt(hour.split(':')[0]);
      return slotHour >= startHour && slotHour < endHour;
    });
  };

  const getSubjectColor = (id: string) => {
    return subjects.find(s => s.id === id)?.color || 'bg-slate-700';
  };

  const getSubjectName = (id: string) => {
    return subjects.find(s => s.id === id)?.name || 'General Task';
  };

  return (
    <div className="space-y-6 md:space-y-8">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-slate-900/40 p-5 md:p-6 rounded-[1.5rem] md:rounded-[2rem] border border-white/5">
        <div>
          <h2 className="text-xl md:text-2xl font-black font-outfit text-white tracking-tight">Weekly Strategy</h2>
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-1">Consistency is key to 3A's</p>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setEntries([])}
            className="flex-1 md:flex-none px-4 md:px-6 py-2.5 md:py-3 rounded-xl md:rounded-2xl bg-slate-800 text-slate-400 hover:text-white transition-all font-black text-[9px] md:text-[10px] uppercase tracking-widest border border-white/5"
          >
            Clear
          </button>
          <button 
            onClick={handleAddClick}
            className="flex-1 md:flex-none px-4 md:px-6 py-2.5 md:py-3 rounded-xl md:rounded-2xl bg-blue-600 text-white hover:bg-blue-500 transition-all font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-xl shadow-blue-900/20"
          >
            Add Block
          </button>
        </div>
      </div>

      <div className="relative group">
        <div className="overflow-x-auto custom-scrollbar pb-6 rounded-[1.5rem] md:rounded-[2rem]">
          <div className="min-w-[800px] sm:min-w-[1000px] glass-card border-white/5 overflow-hidden">
            <div className="grid grid-cols-[80px_repeat(7,1fr)] md:grid-cols-[100px_repeat(7,1fr)] border-b border-white/5">
              <div className="p-3 bg-black/20 text-[9px] md:text-[10px] font-black uppercase text-slate-500 tracking-widest flex items-center justify-center">Time</div>
              {DAYS.map(day => (
                <div key={day} className="p-3 text-center border-l border-white/5 bg-black/10">
                  <span className="text-[9px] md:text-[10px] font-black uppercase text-blue-400 tracking-[0.2em]">{day.substring(0, 3)}</span>
                </div>
              ))}
            </div>

            <div className="max-h-[500px] md:max-h-[600px] overflow-y-auto custom-scrollbar">
              {HOURS.map(hour => (
                <div key={hour} className="grid grid-cols-[80px_repeat(7,1fr)] md:grid-cols-[100px_repeat(7,1fr)] border-b border-white/[0.03]">
                  <div className="p-2 md:p-3 text-[9px] md:text-[10px] font-mono-tech text-slate-600 flex items-center justify-center bg-black/5">{hour}</div>
                  {DAYS.map(day => {
                    const slotEntries = getEntryForSlot(day, hour);
                    return (
                      <div key={`${day}-${hour}`} className="min-h-[50px] md:min-h-[60px] border-l border-white/[0.03] p-1 relative group/slot cursor-pointer" onClick={handleAddClick}>
                        {slotEntries.map(entry => {
                          const isStart = entry.startTime === hour;
                          return (
                            <div 
                              key={entry.id}
                              onClick={(e) => { e.stopPropagation(); handleEditClick(entry); }}
                              className={`absolute inset-x-1 top-1 bottom-1 rounded-lg md:rounded-xl p-1 md:p-2 z-10 transition-all hover:scale-[1.02] shadow-lg ${getSubjectColor(entry.subjectId)} opacity-90 border border-white/10`}
                            >
                              {isStart && (
                                <div className="overflow-hidden">
                                  <p className="text-[8px] md:text-[9px] font-black text-white leading-tight mb-0.5 md:mb-1 truncate">{getSubjectName(entry.subjectId)}</p>
