                          <span className="text-sm md:text-xl text-blue-500/20">+</span>
                        </div>
                      </div>
                    );
                  })}
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Mobile Swipe Hint */}
        <div className="md:hidden absolute top-0 right-0 bottom-0 w-8 pointer-events-none bg-gradient-to-l from-slate-950/40 to-transparent flex items-center justify-center">
            <div className="w-1.5 h-12 bg-white/5 rounded-full" />
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] flex items-end sm:items-center justify-center p-0 sm:p-6 backdrop-blur-md bg-black/60 animate-reveal">
          <div className="glass-card w-full max-w-md p-6 sm:p-8 rounded-t-[2rem] sm:rounded-[2.5rem] border-white/10 shadow-2xl relative pb-[calc(2rem+env(safe-area-inset-bottom))] sm:pb-8">
            <button 
              onClick={() => setShowModal(false)}
              className="absolute top-6 right-6 text-slate-500 hover:text-white transition-colors"
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>

            <h3 className="text-lg md:text-xl font-black font-outfit text-white mb-6 md:mb-8">
              {editingEntry ? 'Edit block' : 'Plan new block'}
            </h3>

            <form onSubmit={handleSave} className="space-y-4 md:space-y-6">
              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Day</label>
                <select 
                  value={formDay}
                  onChange={(e) => setFormDay(e.target.value)}
                  className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3 text-sm text-white focus:outline-none focus:border-blue-500 appearance-none"
                >
                  {DAYS.map(d => <option key={d} value={d} className="bg-slate-900">{d}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-2 gap-3 md:gap-4">
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Start</label>
                  <input type="time" value={formStart} onChange={(e) => setFormStart(e.target.value)} className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3 text-sm text-white focus:outline-none focus:border-blue-500" />
                </div>
                <div className="space-y-1.5">
                  <label className="text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">End</label>
                  <input type="time" value={formEnd} onChange={(e) => setFormEnd(e.target.value)} className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3 text-sm text-white focus:outline-none focus:border-blue-500" />
                </div>
              </div>

              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Subject</label>
                <select 
                  value={formSubjectId}
                  onChange={(e) => setFormSubjectId(e.target.value)}
                  className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3 text-sm text-white focus:outline-none focus:border-blue-500 appearance-none"
                >
                  {subjects.map(s => <option key={s.id} value={s.id} className="bg-slate-900">{s.name}</option>)}
                  <option value="custom" className="bg-slate-900">Break / Personal</option>
                </select>
              </div>

              <div className="space-y-1.5">
                <label className="text-[9px] md:text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Note</label>
                <input type="text" value={formNote} onChange={(e) => setFormNote(e.target.value)} placeholder="Topic name..." className="w-full bg-slate-900/50 border border-slate-700/50 rounded-xl md:rounded-2xl px-4 py-2.5 md:py-3 text-sm text-white focus:outline-none focus:border-blue-500" />
              </div>

              <div className="flex gap-2 md:gap-3 pt-4">
                {editingEntry && (
                  <button type="button" onClick={() => handleDelete(editingEntry.id)} className="flex-1 py-3.5 md:py-4 bg-red-500/10 text-red-400 rounded-xl md:rounded-2xl font-black text-[9px] md:text-[10px] uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all">Delete</button>
                )}
                <button type="submit" className="flex-[2] py-3.5 md:py-4 bg-blue-600 text-white rounded-xl md:rounded-2xl font-black text-[9px] md:text-[10px] uppercase tracking-widest hover:bg-blue-500 transition-all shadow-xl">
                  {editingEntry ? 'Update' : 'Confirm'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TimetablePage;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithStudyBuddy } from '../services/geminiService';

const AIChatBuddy: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (error) {
      const timer = setTimeout(() => setError(null), 8000);
      return () => clearTimeout(timer);
    }
  }, [error]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setError(null);

    try {
      const response = await chatWithStudyBuddy([...messages, userMsg], currentInput);
      const botMsg: ChatMessage = { role: 'model', text: response, timestamp: Date.now() };
      setMessages(prev => [...prev, botMsg]);
    } catch (err: any) {
      setError("AI Service busy. Please try again.");
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="glass-card rounded-[1.5rem] md:rounded-[2.5rem] p-4 md:p-8 border-indigo-500/10 flex flex-col h-[70vh] md:h-[calc(100vh-280px)] min-h-[500px] relative shadow-2xl w-full">
      <div className="absolute inset-0 bg-indigo-600/5 pointer-events-none rounded-[1.5rem] md:rounded-[2.5rem]" />

      {error && (
        <div className="absolute top-4 left-4 right-4 z-50 animate-reveal">
          <div className="bg-red-500/10 backdrop-blur-xl border border-red-500/30 rounded-2xl p-4 flex items-center justify-between shadow-2xl">
            <span className="text-[10px] font-bold text-red-200">⚠️ {error}</span>
            <button onClick={() => setError(null)} className="text-red-400">✕</button>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between mb-4 md:mb-6 shrink-0 relative z-10">
        <div className="flex items-center gap-2 md:gap-3">
          <div className="w-8 h-8 md:w-10 md:h-10 rounded-xl md:rounded-2xl bg-indigo-600 flex items-center justify-center text-white shadow-lg">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" viewBox="0 0 20 20" fill="currentColor">
              <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM7 9a1 1 0 100-2 1 1 0 000 2zm7-1a1 1 0 11-2 0 1 1 0 012 0zm-7.535 5.503a1 1 0 10-1.415 1.414 3 3 0 004.242 0 1 1 0 00-1.415-1.414 1 1 0 01-1.412 0z" clipRule="evenodd" />
            </svg>
          </div>
          <div>
            <h3 className="font-black text-xs md:text-sm uppercase tracking-widest text-white leading-none">A/L Buddy</h3>
            <span className="text-[8px] md:text-[10px] text-indigo-400 font-bold uppercase tracking-tighter">Gemini Intelligence</span>
          </div>
        </div>
        <div className={`w-2 h-2 rounded-full ${isTyping ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'} shadow-lg`} />
      </div>

      <div ref={scrollRef} className="flex-1 overflow-y-auto pr-1 md:pr-2 custom-scrollbar space-y-4 md:space-y-6 mb-4 relative z-10">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-4">
            <div className="w-16 h-16 md:w-20 md:h-20 bg-indigo-500/5 rounded-full flex items-center justify-center text-3xl md:text-4xl mb-6 border border-indigo-500/10 grayscale opacity-40">🎓</div>
            <p className="text-slate-500 text-[10px] md:text-xs leading-relaxed max-w-xs font-bold uppercase tracking-widest">Consultant Active</p>
            <div className="grid grid-cols-1 gap-2 mt-8 w-full max-w-xs">
              {['"Explain Laws of Friction"', '"ICT logic gate help"', '"Pure Maths study plan"'].map(prompt => (
                <button 
                  key={prompt}
                  onClick={() => setInput(prompt.replace(/"/g, ''))}
                  className="p-3 text-[9px] md:text-[10px] font-bold text-slate-400 bg-slate-900/50 border border-white/5 rounded-xl hover:bg-indigo-600 hover:text-white transition-all text-left"
                >
                  {prompt}
                </button>
              ))}
            </div>
          </div>
        )}

        {messages.map((msg, i) => (
          <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-reveal`}>
            <div className={`max-w-[90%] md:max-w-[85%] p-3 md:p-4 rounded-2xl text-xs md:text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-gradient-to-br from-indigo-600 to-blue-700 text-white rounded-tr-none' 
                : 'bg-slate-900/90 text-slate-200 border border-white/5 rounded-tl-none'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-reveal">
            <div className="bg-slate-900/90 p-3 rounded-2xl rounded-tl-none flex gap-1 items-center border border-white/5">
              <div className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce" />
              <div className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.2s]" />
              <div className="w-1 h-1 bg-indigo-500 rounded-full animate-bounce [animation-delay:0.4s]" />
            </div>
          </div>
        )}
      </div>

      <form onSubmit={handleSend} className="relative mt-auto shrink-0 z-20">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask anything..."
          className="w-full bg-slate-950/80 border border-white/10 rounded-xl md:rounded-2xl px-4 py-3 md:py-4 text-xs md:text-sm text-white focus:outline-none focus:border-indigo-500 transition-all pr-12"
        />
        <button 
          type="submit"
          disabled={isTyping || !input.trim()}
          className="absolute right-2 top-2 bottom-2 w-8 h-8 md:w-10 md:h-10 flex items-center justify-center rounded-lg md:rounded-xl bg-indigo-600 text-white hover:bg-indigo-500 transition-all disabled:opacity-30 active:scale-95 shadow-lg"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5" viewBox="0 0 20 20" fill="currentColor">
            <path d="M10.894 2.553a1 1 0 00-1.788 0l-7 14a1 1 0 001.169 1.409l5-1.429A1 1 0 009 15.571V11a1 1 0 112 0v4.571a1 1 0 00.725.962l5 1.428a1 1 0 001.17-1.408l-7-14z" />
          </svg>
        </button>
      </form>
    </div>
  );
};

export default AIChatBuddy;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, AL_STREAMS } from './constants';
import { TimeLeft, Subject, User, Goal } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import CreditsPage from './components/CreditsPage';
import TimetablePage from './components/TimetablePage';
import OverallStats from './components/OverallStats';
import { fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

type View = 'dashboard' | 'curriculum' | 'tools' | 'chat' | 'timetable' | 'stats' | 'credits';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [currentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  useEffect(() => {
    const savedGoals = localStorage.getItem('al_2026_goals');
    if (savedGoals) setGoals(JSON.parse(savedGoals));
  }, [activeView]);

  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  useEffect(() => {
    const savedUser = localStorage.getItem('al_2026_user');
    if (savedUser) {
      const parsedUser = JSON.parse(savedUser);
      setUser(parsedUser);

      const savedSubjects = localStorage.getItem(`al_2026_subjects_${parsedUser.streamId}`);
      if (savedSubjects) {
        setSubjects(JSON.parse(savedSubjects));
      } else {
        const defaultStream = AL_STREAMS.find(s => s.id === parsedUser.streamId) || AL_STREAMS[0];
        setSubjects(defaultStream.subjects);
      }
    }
    setIsAuthLoading(false);
  }, []);

  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`al_2026_subjects_${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    if (remember) localStorage.setItem('al_2026_user', JSON.stringify(newUser));
    const stream = AL_STREAMS.find(s => s.id === streamId) || AL_STREAMS[0];
    setSubjects(stream.subjects);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('al_2026_user');
    setSubjects([]);
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0) {
      refreshNews();
    }
  }, [user, timeLeft.days]);

  if (isAuthLoading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center gap-4">
      <div className="w-12 h-12 rounded-2xl border-4 border-blue-500/20 border-t-blue-500 animate-spin" />
      <span className="text-[10px] font-black uppercase tracking-[0.2em] text-blue-400">Syncing Data</span>
    </div>
  );

  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="flex flex-col gap-8 md:gap-12 animate-reveal">
            {/* Hero Section - Centered and Huge on TV/PC */}
            <section className="text-center w-full max-w-[100rem] mx-auto py-4 md:py-12">
              <div className="inline-block mb-6 px-4 py-2 md:px-12 md:py-4 rounded-full bg-blue-500/5 border border-blue-500/10 shadow-[0_0_50px_rgba(59,130,246,0.05)] animate-float">
                <span className="text-xs sm:text-lg md:text-3xl font-black font-outfit text-transparent bg-clip-text bg-gradient-to-r from-amber-400 via-yellow-200 to-amber-500">
                  ✨ 3A's ARE THE ONLY OPTION
                </span>
              </div>
              <h1 className="text-fluid-h1 font-black font-outfit mb-8 md:mb-12 tracking-tighter leading-none text-white px-2">
                Targeting <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-indigo-400">Success.</span>
              </h1>
              <div className="w-full">
                <CountdownCard timeLeft={timeLeft} />
              </div>
            </section>

            {/* Dashboard Content Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-10 xl:gap-tv max-w-tv mx-auto w-full">
              {/* Main Column */}
              <div className="lg:col-span-8 space-y-8 md:space-y-12">
                <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
                <div className="hidden lg:block">
                   <AIChatBuddy />
                </div>
              </div>

              {/* Side Column */}
              <div className="lg:col-span-4 space-y-8 md:space-y-10">
                <div className="glass-card rounded-[2.5rem] md:rounded-[3rem] p-6 md:p-10 border border-emerald-500/10 relative overflow-hidden group">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-[50px] rounded-full group-hover:bg-emerald-500/10 transition-all" />
                  <h4 className="font-black text-[10px] md:text-xs uppercase tracking-widest mb-6 md:mb-8 text-emerald-400">📊 Batch Index</h4>
                  <div className="space-y-6 md:space-y-8">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] md:text-xs text-slate-500 font-bold uppercase tracking-widest">Progress</span>
                      <span className="text-emerald-400 font-black text-2xl md:text-5xl font-mono-tech leading-none tracking-tighter">~{batchIndex}%</span>
                    </div>
                    <div className="w-full bg-slate-950 rounded-full h-3 md:h-5 p-1 border border-slate-800">
                      <div className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full rounded-full transition-all duration-1000" style={{ width: `${batchIndex}%` }} />
                    </div>
                  </div>
                </div>
                <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
                <StudyGoals />
                <div className="lg:hidden">
                   <AIChatBuddy />
                </div>
              </div>
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-12 animate-reveal max-w-tv mx-auto w-full">
            <div className="lg:col-span-8">
              <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
            </div>
            <div className="lg:col-span-4">
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 md:gap-12 animate-reveal max-w-tv mx-auto w-full items-stretch">
            <FocusTimer />
            <ResourceVault />
          </div>
        );
      case 'chat':
        return (
          <div className="max-w-6xl mx-auto animate-reveal w-full p-2 md:p-8">
            <AIChatBuddy />
          </div>
        );
      case 'timetable':
        return (
          <div className="animate-reveal w-full max-w-tv mx-auto">
            <TimetablePage subjects={subjects} />
          </div>
        );
      case 'stats':
        return (
          <div className="animate-reveal w-full max-w-tv mx-auto">
            <OverallStats subjects={subjects} goals={goals} />
          </div>
        );
      case 'credits':
        return (
          <div className="max-w-4xl mx-auto animate-reveal w-full">
            <CreditsPage />
          </div>
        );
      default:
        return null;
    }
  };

  return (
