}

const CountdownCard: React.FC<CountdownCardProps> = ({ timeLeft }) => {
  const Unit: React.FC<{ value: number; label: string; colorClass: string }> = ({ value, label, colorClass }) => {
    const formattedValue = value.toString().padStart(2, '0');

    return (
      <div className="flex flex-col items-center group w-full">
        <div className="countdown-card rounded-[2rem] md:rounded-[3rem] p-4 md:p-10 xl:p-14 w-full transition-all duration-700 hover:translate-y-[-10px] hover:border-blue-400/40 relative flex flex-col items-center justify-center shadow-2xl overflow-hidden">
          {/* Immersive glow */}
          <div className={`absolute -right-10 -bottom-10 w-40 h-40 rounded-full blur-[100px] opacity-10 group-hover:opacity-30 transition-all duration-700 ${colorClass}`} />

          <div className="flex gap-2 md:gap-4 xl:gap-6 mb-4 md:mb-8">
            {formattedValue.split('').map((digit, idx) => (
              <div 
                key={idx} 
                className="digit-box rounded-2xl md:rounded-[2.5rem] w-12 h-16 sm:w-16 sm:h-24 md:w-28 md:h-44 xl:w-40 xl:h-60 flex items-center justify-center relative overflow-hidden"
              >
                <div className="absolute top-1/2 left-0 w-full h-[1px] bg-white/5 z-10" />
                <span 
                  className="text-3xl sm:text-5xl md:text-8xl xl:text-[10rem] font-black font-mono-tech text-white relative z-0 tracking-tighter"
                >
                  {digit}
                </span>
              </div>
            ))}
          </div>

          <div className="flex items-center gap-3 md:gap-5">
            <div className={`w-2 h-2 md:w-4 md:h-4 rounded-full ${colorClass} animate-pulse shadow-[0_0_15px_rgba(59,130,246,0.5)]`} />
            <span className="text-[9px] sm:text-xs md:text-xl uppercase tracking-[0.4em] text-slate-400 font-black font-outfit whitespace-nowrap">
              {label}
            </span>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 sm:gap-6 md:gap-10 xl:gap-16 w-full max-w-[120rem] mx-auto px-4 md:px-10">
      <Unit value={timeLeft.days} label="Days" colorClass="bg-blue-500" />
      <Unit value={timeLeft.hours} label="Hours" colorClass="bg-indigo-500" />
      <Unit value={timeLeft.minutes} label="Minutes" colorClass="bg-purple-500" />
      <Unit value={timeLeft.seconds} label="Seconds" colorClass="bg-cyan-500" />
    </div>
  );
};

