import React, { useState, useMemo } from 'react';
import { AL_STREAMS } from '../constants';
import { Subject } from '../types';

interface LoginPageProps {
  onLogin: (name: string, remember: boolean, streamId: string, selectedSubjects: Subject[]) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [streamId, setStreamId] = useState('');
  const [selectedSubjectIds, setSelectedSubjectIds] = useState<string[]>([]);
  const [remember, setRemember] = useState(true);
  const [error, setError] = useState('');

  const selectedStream = useMemo(() => 
    AL_STREAMS.find(s => s.id === streamId), 
  [streamId]);

  const toggleSubject = (id: string) => {
    setError('');
    setSelectedSubjectIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(sid => sid !== id);
      }
      if (prev.length >= 3) {
        setError('Standard A/L candidates pick 3 subjects.');
        return prev;
      }
      return [...prev, id];
    });
  };

  const handleNext = () => {
    if (step === 1) {
      if (!name.trim() || name.length < 2) {
        setError('Please enter a valid candidate name.');
        return;
      }
      setStep(2);
      setError('');
    } else if (step === 2) {
      if (!streamId) {
        setError('Please select your academic stream.');
        return;
      }
      setStep(3);
      setError('');
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedSubjectIds.length < 3) {
      setError('Please select exactly 3 subjects.');
      return;
    }

    const finalSubjects = selectedStream?.subjects.filter(s => 
      selectedSubjectIds.includes(s.id)
    ) || [];

    onLogin(name, remember, streamId, finalSubjects);
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-6 relative overflow-hidden">
      <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/10 blur-[120px] rounded-full animate-float" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 blur-[120px] rounded-full animate-float" style={{ animationDelay: '3s' }} />

      <div className="glass-card w-full max-w-2xl p-8 md:p-12 rounded-[2.5rem] relative z-10 animate-reveal">
        {/* Step Indicator */}
        <div className="flex justify-center gap-3 mb-12">
          {[1, 2, 3].map(i => (
            <div 
              key={i} 
              className={`h-1.5 rounded-full transition-all duration-500 ${
                step === i ? 'w-12 bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 
                step > i ? 'w-6 bg-blue-500/40' : 'w-6 bg-slate-800'
              }`}
            />
          ))}
        </div>

        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl flex items-center justify-center font-black text-4xl shadow-2xl shadow-blue-900/40 text-white mx-auto mb-6 transform rotate-6 hover:rotate-0 transition-transform duration-500">A</div>
          <h1 className="text-3xl font-black font-outfit text-white tracking-tighter uppercase">Profile Setup</h1>
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest mt-2">GCE A/L Batch 2026 Batch Precision Hub</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-8">
          {step === 1 && (
            <div className="max-w-md mx-auto animate-reveal">
              <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2 ml-1">Candidate Identifier</label>
              <input
                type="text"
                autoFocus
                value={name}
                onChange={(e) => { setName(e.target.value); setError(''); }}
                placeholder="How should we address you?"
                className="w-full bg-slate-900/50 border border-slate-700/50 rounded-2xl px-5 py-4 text-white placeholder-slate-600 focus:outline-none focus:border-blue-500 transition-all font-medium text-lg"
              />
              <p className="text-[10px] text-slate-600 mt-4 px-2 leading-relaxed">This name will be used on your performance reports and AI Study Buddy consultations.</p>
            </div>
          )}

          {step === 2 && (
            <div className="animate-reveal">
              <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-6 ml-1">Academic Category</label>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {AL_STREAMS.map(stream => (
                  <button
                    key={stream.id}
                    type="button"
                    onClick={() => { setStreamId(stream.id); setError(''); }}
                    className={`text-left p-6 rounded-[2rem] border transition-all duration-300 relative group overflow-hidden ${
                      streamId === stream.id 
                        ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_30px_rgba(59,130,246,0.1)]' 
                        : 'bg-slate-950/40 border-slate-800 hover:border-slate-700'
                    }`}
                  >
                    <h3 className={`text-sm font-black mb-1 ${streamId === stream.id ? 'text-blue-400' : 'text-slate-200'}`}>
                      {stream.name}
                    </h3>
                    <p className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter">
                      {stream.subjects.length} Core Modules Available
                    </p>
                    {streamId === stream.id && (
                      <div className="absolute top-4 right-4 text-blue-500">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd" />
                        </svg>
                      </div>
                    )}
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 3 && selectedStream && (
            <div className="animate-reveal">
              <div className="flex justify-between items-center mb-6 px-1">
                <label className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Select 3 Core Subjects</label>
                <span className={`text-[10px] font-black px-3 py-1 rounded-full ${selectedSubjectIds.length === 3 ? 'bg-emerald-500 text-white' : 'bg-blue-500 text-white'}`}>
                  {selectedSubjectIds.length} / 3 Selected
                </span>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar">
                {selectedStream.subjects.map(subject => {
                  const isSelected = selectedSubjectIds.includes(subject.id);
                  return (
                    <button
                      key={subject.id}
                      type="button"
                      onClick={() => toggleSubject(subject.id)}
                      className={`flex items-center gap-4 p-4 rounded-2xl border transition-all text-left ${
                        isSelected 
                          ? 'bg-blue-600/10 border-blue-500' 
                          : 'bg-slate-900/40 border-slate-800 hover:border-slate-700'
                      }`}
                    >
                      <div className={`w-3 h-3 rounded-full shrink-0 border-2 ${isSelected ? 'bg-blue-500 border-blue-400' : 'border-slate-700'}`} />
                      <div>
                        <p className={`text-xs font-black tracking-tight ${isSelected ? 'text-white' : 'text-slate-400'}`}>
                          {subject.name}
                        </p>
                        <p className="text-[8px] text-slate-500 font-bold uppercase mt-0.5">
                          {subject.units.length} Syllabus Units
                        </p>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          <div className="max-w-md mx-auto space-y-6">
            {error && (
              <div className="p-4 rounded-2xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold text-center animate-shake">
                ⚠️ {error}
              </div>
            )}

            <div className="flex gap-4">
              {step > 1 && (
                <button
                  type="button"
                  onClick={() => { setStep(prev => prev - 1); setError(''); }}
                  className="flex-1 py-5 bg-slate-900 text-slate-400 font-black uppercase tracking-[0.2em] rounded-2xl border border-white/5 hover:text-white transition-all"
                >
                  Back
                </button>
              )}
              {step < 3 ? (
                <button
                  type="button"
                  onClick={handleNext}
                  className="flex-[2] py-5 bg-blue-600 text-white font-black uppercase tracking-[0.2em] rounded-2xl shadow-xl shadow-blue-900/30 hover:bg-blue-500 transition-all active:scale-[0.98]"
                >
                  Continue
                </button>
              ) : (
                <button
                  type="submit"
                  className="flex-[2] py-5 bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-500 hover:to-indigo-500 text-white font-black uppercase tracking-[0.2em] rounded-2xl shadow-xl shadow-blue-900/30 transition-all transform active:scale-[0.98]"
                >
                  Launch Success Hub
                </button>
              )}
            </div>

            <label className="flex items-center justify-center gap-3 cursor-pointer group pt-4">
              <input
                type="checkbox"
                checked={remember}
