import React, { useState, useMemo, useEffect } from 'react';
import { AL_STREAMS } from '../constants';
import { Subject } from '../types';

interface LoginPageProps {
  onLogin: (name: string, remember: boolean, streamId: string, selectedSubjects: Subject[]) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [streamId, setStreamId] = useState('');
  const [selectedSubjectIds, setSelectedSubjectIds] = useState<string[]>([]);
  const [remember, setRemember] = useState(true);
  const [error, setError] = useState('');

  // Clear error when inputs change
  useEffect(() => {
    setError('');
  }, [name, streamId, selectedSubjectIds, step]);

  const selectedStream = useMemo(() => 
    AL_STREAMS.find(s => s.id === streamId), 
  [streamId]);

  // Common combinations logic for quick selection
  const commonCombos = useMemo(() => {
    if (!selectedStream) return [];
    if (streamId === 'maths') return [['cm', 'ph', 'ch'], ['cm', 'ph', 'ict']];
    if (streamId === 'bio') return [['bi', 'ch', 'ph'], ['bi', 'ch', 'ag']];
    if (streamId === 'commerce') return [['ac', 'bs', 'ec'], ['ac', 'ec', 'ict']];
    if (streamId === 'arts') return [['lo', 'ps', 'ec'], ['sin', 'his', 'ps']];
    if (streamId === 'tech') return [['et', 'st', 'ict'], ['bt', 'st', 'ag']];
    return [];
  }, [streamId, selectedStream]);

  const applyCombo = (ids: string[]) => {
    setSelectedSubjectIds(ids);
  };

  const toggleSubject = (id: string) => {
    setSelectedSubjectIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(sid => sid !== id);
      }
      if (prev.length >= 3) {
        return prev; // Error is handled by UI feedback now
      }
      return [...prev, id];
    });
  };

  const handleNext = () => {
    if (step === 1) {
      if (!name.trim() || name.length < 2) {
        setError('Please enter your full name (min 2 chars).');
        return;
      }
      setStep(2);
    } else if (step === 2) {
      if (!streamId) {
        setError('Please select an academic stream to continue.');
        return;
      }
      setStep(3);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedSubjectIds.length !== 3) {
      setError('A standard A/L profile requires exactly 3 subjects.');
      return;
    }

    const finalSubjects = selectedStream?.subjects
      .filter(s => selectedSubjectIds.includes(s.id))
      .map(s => JSON.parse(JSON.stringify(s))) || []; // Deep clone to avoid mutation of constants

    onLogin(name, remember, streamId, finalSubjects);
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-6 relative overflow-hidden bg-[#020617]">
      {/* Immersive Background Orbs */}
      <div className="absolute top-[-10%] right-[-10%] w-[60%] h-[60%] bg-blue-600/10 blur-[120px] rounded-full animate-pulse" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-600/10 blur-[120px] rounded-full animate-pulse" style={{ animationDelay: '2s' }} />

      <div className="glass-card w-full max-w-xl p-8 md:p-12 rounded-[2.5rem] relative z-10 shadow-2xl border-white/5">

        {/* Step Progress Bar */}
        <div className="flex gap-2 mb-10">
          {[1, 2, 3].map(i => (
            <div key={i} className="flex-1 h-1.5 rounded-full bg-slate-800 overflow-hidden">
              <div 
                className={`h-full transition-all duration-700 ease-out ${
                  step >= i ? 'bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]' : 'w-0'
                }`}
                style={{ width: step >= i ? '100%' : '0%' }}
              />
            </div>
          ))}
        </div>

        <div className="text-center mb-10">
          <div className="w-16 h-16 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl flex items-center justify-center font-black text-3xl shadow-2xl text-white mx-auto mb-6 transform rotate-3">A</div>
          <h1 className="text-2xl font-black font-outfit text-white tracking-tight uppercase">
            {step === 1 ? 'Identify Yourself' : step === 2 ? 'Choose Your Stream' : 'Select Subjects'}
          </h1>
          <p className="text-slate-500 text-[9px] font-black uppercase tracking-[0.2em] mt-2">GCE A/L 2026 Candidate Portal</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          {step === 1 && (
            <div className="animate-reveal space-y-4">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-500 ml-1">Full Name</label>
                <input
                  type="text"
                  autoFocus
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="e.g., Chamath Perera"
                  className="w-full bg-slate-900/50 border border-slate-700/50 rounded-2xl px-5 py-4 text-white placeholder-slate-600 focus:outline-none focus:border-blue-500 transition-all font-medium"
                />
              </div>
              <p className="text-[10px] text-slate-500 leading-relaxed px-1">
                Your data is stored locally. This name will appear on your personalized study dashboard and reports.
              </p>
            </div>
          )}

          {step === 2 && (
            <div className="animate-reveal grid grid-cols-1 gap-3 max-h-[400px] overflow-y-auto pr-1 custom-scrollbar">
              {AL_STREAMS.map(stream => (
                <button
                  key={stream.id}
                  type="button"
                  onClick={() => setStreamId(stream.id)}
                  className={`text-left p-5 rounded-2xl border transition-all relative group ${
                    streamId === stream.id 
                      ? 'bg-blue-600/10 border-blue-500 shadow-lg' 
                      : 'bg-slate-900/40 border-slate-800 hover:border-slate-700'
                  }`}
                >
                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className={`text-sm font-black ${streamId === stream.id ? 'text-blue-400' : 'text-slate-200'}`}>
                        {stream.name}
                      </h3>
                      <p className="text-[9px] text-slate-500 font-bold uppercase tracking-tighter mt-1">
                        {stream.subjects.length} Subjects in Pool
                      </p>
                    </div>
                    {streamId === stream.id && (
                      <div className="w-5 h-5 bg-blue-500 rounded-full flex items-center justify-center">
                        <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                        </svg>
                      </div>
                    )}
                  </div>
                </button>
              ))}
            </div>
          )}

          {step === 3 && selectedStream && (
            <div className="animate-reveal space-y-6">
              {/* Quick Picks */}
              {commonCombos.length > 0 && (
                <div className="space-y-3">
                  <label className="text-[9px] font-black uppercase tracking-widest text-slate-500">Quick Combinations</label>
                  <div className="flex flex-wrap gap-2">
                    {commonCombos.map((combo, idx) => (
                      <button
                        key={idx}
                        type="button"
                        onClick={() => applyCombo(combo)}
                        className="px-3 py-2 rounded-xl bg-slate-900 border border-slate-800 text-[9px] font-black text-slate-400 hover:text-white hover:border-blue-500/50 transition-all uppercase"
                      >
                        Combo {idx + 1}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <div className="space-y-3">
                <div className="flex justify-between items-center px-1">
                  <label className="text-[9px] font-black uppercase tracking-widest text-slate-500">Individual Selection</label>
                  <span className={`text-[10px] font-black ${selectedSubjectIds.length === 3 ? 'text-emerald-400' : 'text-blue-400'}`}>
                    {selectedSubjectIds.length}/3
                  </span>
                </div>
                <div className="grid grid-cols-1 gap-2 max-h-[300px] overflow-y-auto pr-2 custom-scrollbar">
                  {selectedStream.subjects.map(subject => {
                    const isSelected = selectedSubjectIds.includes(subject.id);
                    return (
                      <button
                        key={subject.id}
                        type="button"
                        onClick={() => toggleSubject(subject.id)}
                        disabled={!isSelected && selectedSubjectIds.length >= 3}
                        className={`flex items-center gap-4 p-4 rounded-xl border transition-all text-left ${
                          isSelected 
                            ? 'bg-blue-600/10 border-blue-500' 
                            : 'bg-slate-900/40 border-slate-800 hover:border-slate-700 disabled:opacity-40 disabled:grayscale'
                        }`}
                      >
                        <div className={`w-3 h-3 rounded-full border-2 transition-all ${isSelected ? 'bg-blue-500 border-blue-400 scale-110' : 'border-slate-700'}`} />
                        <span className={`text-xs font-bold ${isSelected ? 'text-white' : 'text-slate-400'}`}>
                          {subject.name}
                        </span>
                      </button>
                    );
                  })}
                </div>
              </div>
            </div>
          )}

          {error && (
            <div className="p-4 rounded-2xl bg-red-500/10 border border-red-500/20 text-red-400 text-[10px] font-bold text-center animate-bounce">
              ⚠️ {error}
            </div>
          )}

          <div className="flex gap-3 pt-4">
            {step > 1 && (
              <button
                type="button"
                onClick={() => setStep(prev => prev - 1)}
                className="flex-1 py-4 bg-slate-900 text-slate-400 font-black uppercase tracking-widest rounded-2xl border border-white/5 hover:text-white transition-all"
              >
                Back
              </button>
            )}
            {step < 3 ? (
              <button
                type="button"
                onClick={handleNext}
                className="flex-[2] py-4 bg-blue-600 text-white font-black uppercase tracking-widest rounded-2xl shadow-xl hover:bg-blue-500 transition-all"
              >
                Continue
              </button>
            ) : (
              <button
                type="submit"
                className="flex-[2] py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white font-black uppercase tracking-widest rounded-2xl shadow-xl hover:opacity-90 transition-all"
              >
                Launch Hub
              </button>
            )}
          </div>

          <label className="flex items-center justify-center gap-3 cursor-pointer group pt-4">
            <input
              type="checkbox"
              checked={remember}
              onChange={(e) => setRemember(e.target.checked)}
              className="sr-only peer"
            />
            <div className="w-4 h-4 rounded border border-slate-700 bg-slate-900 peer-checked:bg-blue-600 peer-checked:border-blue-600 transition-all flex items-center justify-center">
              <svg className="w-2.5 h-2.5 text-white opacity-0 peer-checked:opacity-100 transition-opacity" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={4}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-600 group-hover:text-slate-400">Remember Profile</span>
          </label>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, AL_STREAMS } from './constants';
import { TimeLeft, Subject, User, Goal } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import CreditsPage from './components/CreditsPage';
import TimetablePage from './components/TimetablePage';
import OverallStats from './components/OverallStats';
import { fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

type View = 'dashboard' | 'curriculum' | 'tools' | 'chat' | 'timetable' | 'stats' | 'credits';

const STORAGE_KEYS = {
  USER: 'al_2026_user_v2',
  SUBJECTS_PREFIX: 'al_2026_subjects_v2_',
  GOALS: 'al_2026_goals_v2'
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [currentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  // Calculate Batch Index
  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  // Load User and Subjects on Init
  useEffect(() => {
    const initApp = async () => {
      try {
        const savedUserJson = localStorage.getItem(STORAGE_KEYS.USER);
        if (savedUserJson) {
          const parsedUser = JSON.parse(savedUserJson) as User;
          setUser(parsedUser);

          const savedSubjectsJson = localStorage.getItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${parsedUser.streamId}`);
          if (savedSubjectsJson) {
            setSubjects(JSON.parse(savedSubjectsJson));
          }
        }

        const savedGoals = localStorage.getItem(STORAGE_KEYS.GOALS);
        if (savedGoals) setGoals(JSON.parse(savedGoals));

      } catch (err) {
        console.error("Initialization Error:", err);
        localStorage.clear(); // Clear corrupt data
      } finally {
        setIsAuthLoading(false);
      }
    };

    initApp();
  }, []);

  // Persist Subjects when they change
  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string, selectedSubjects: Subject[]) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    setSubjects(selectedSubjects);

    if (remember) {
      localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(newUser));
      localStorage.setItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${streamId}`, JSON.stringify(selectedSubjects));
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem(STORAGE_KEYS.USER);
    setSubjects([]);
    setActiveView('dashboard');
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    if (isLoadingNews) return;
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0 && !news) {
      refreshNews();
    }
  }, [user, timeLeft.days, news]);

  if (isAuthLoading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center gap-4">
      <div className="w-10 h-10 rounded-xl border-4 border-blue-500/10 border-t-blue-500 animate-spin" />
      <span className="text-[9px] font-black uppercase tracking-widest text-blue-400 opacity-60">Syncing Profile</span>
    </div>
  );

  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="flex flex-col gap-10 md:gap-16 animate-reveal">
            <section className="text-center w-full max-w-6xl mx-auto py-6 md:py-16">
              <div className="inline-block mb-6 px-6 py-2 rounded-full bg-blue-500/5 border border-blue-500/10 shadow-sm animate-float">
                <span className="text-xs md:text-sm font-black font-outfit text-transparent bg-clip-text bg-gradient-to-r from-amber-400 to-amber-600">
                  ✨ TARGET: 3A's - BATCH 2026
                </span>
              </div>
              <h1 className="text-fluid-h1 font-black font-outfit mb-12 tracking-tighter leading-none text-white">
                Success is <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 to-indigo-400">Inevitability.</span>
              </h1>
              <CountdownCard timeLeft={timeLeft} />
            </section>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 max-w-tv mx-auto w-full">
              <div className="lg:col-span-8 space-y-10">
                <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
                <AIChatBuddy />
              </div>

              <div className="lg:col-span-4 space-y-8">
                <div className="glass-card rounded-[2.5rem] p-8 border border-emerald-500/10 relative overflow-hidden group">
                  <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 blur-[60px] rounded-full" />
                  <h4 className="font-black text-[10px] uppercase tracking-widest mb-6 text-emerald-400">📊 Batch Index</h4>
                  <div className="space-y-6">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Mastery</span>
                      <span className="text-emerald-400 font-black text-4xl font-mono-tech leading-none">~{batchIndex}%</span>
                    </div>
                    <div className="w-full bg-slate-950 rounded-full h-3 p-0.5 border border-slate-800">
                      <div className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full rounded-full transition-all duration-1000" style={{ width: `${batchIndex}%` }} />
                    </div>
                  </div>
                </div>
                <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
                <StudyGoals />
              </div>
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-reveal max-w-tv mx-auto w-full">
            <div className="lg:col-span-8">
              <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
            </div>
            <div className="lg:col-span-4">
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 animate-reveal max-w-tv mx-auto w-full">
            <FocusTimer />
            <ResourceVault />
          </div>
        );
      case 'timetable':
        return <TimetablePage subjects={subjects} />;
      case 'stats':
        return <OverallStats subjects={subjects} goals={goals} />;
      case 'credits':
        return <CreditsPage />;
      case 'chat':
        return (
          <div className="max-w-4xl mx-auto w-full h-[80vh]">
            <AIChatBuddy />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-40 selection:bg-blue-500/30">
      <nav className="px-6 py-6 md:px-12 md:py-8 flex justify-between items-center max-w-[100rem] mx-auto sticky top-0 z-50 backdrop-blur-xl bg-slate-950/20">
        <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveView('dashboard')}>
          <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center font-black text-2xl text-white shadow-xl transform group-hover:rotate-0 transition-transform rotate-6">A</div>
          <div className="flex flex-col">
            <span className="text-xl font-black tracking-tighter font-outfit uppercase leading-none text-white">AL 2026</span>
            <span className="text-[8px] text-blue-400 font-bold tracking-[0.3em] uppercase mt-1">Strategic Hub</span>
          </div>
        </div>
        <div className="flex items-center gap-6">
          <div className="text-right hidden sm:block">
            <p className="text-[9px] font-black uppercase tracking-widest text-slate-500">Candidate</p>
            <p className="text-sm font-bold text-white">{user.name}</p>
          </div>
          <button onClick={handleLogout} className="p-3 rounded-xl bg-white/5 hover:bg-red-500/10 text-slate-500 hover:text-red-400 transition-all border border-white/5">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
          </button>
        </div>
      </nav>

      <main className="px-6 md:px-12 max-w-[100rem] mx-auto pt-6">
        {renderView()}
      </main>

      {/* Persistent Bottom Nav */}
      <div className="fixed bottom-8 left-1/2 -translate-x-1/2 z-[100] w-[95%] max-w-3xl">
        <div className="glass-card rounded-[2.5rem] p-2 flex items-center justify-between border-white/10 shadow-2xl bg-slate-950/90">
          {[
            { id: 'dashboard', label: 'Home', icon: 'M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z' },
            { id: 'curriculum', label: 'Lessons', icon: 'M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z' },
            { id: 'timetable', label: 'Routine', icon: 'M6 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-1V3a1 1 0 10-2 0v1H7V3a1 1 0 00-1-1zm0 5a1 1 0 000 2h8a1 1 0 100-2H6z' },
            { id: 'stats', label: 'Analysis', icon: 'M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z' },
            { id: 'chat', label: 'AI Buddy', icon: 'M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z' }
          ].map((nav) => (
            <button 
              key={nav.id}
              onClick={() => setActiveView(nav.id as View)}
              className={`flex-1 py-4 rounded-[2rem] flex flex-col items-center gap-1 transition-all group ${activeView === nav.id ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-500 hover:text-slate-200 hover:bg-white/5'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor">
                <path d={nav.icon} />
              </svg>
              <span className="text-[9px] font-black uppercase tracking-widest">{nav.label}</span>
            </button>
          ))}
        </div>
      </div>

      <footer className="mt-24 py-12 text-center opacity-30">
        <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500">System Secure • Official Batch 2026 Registry</p>
      </footer>
    </div>
  );
};

