import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, AL_STREAMS } from './constants';
import { TimeLeft, Subject, User, Goal } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import CreditsPage from './components/CreditsPage';
import TimetablePage from './components/TimetablePage';
import OverallStats from './components/OverallStats';
import { fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

type View = 'dashboard' | 'curriculum' | 'tools' | 'chat' | 'timetable' | 'stats' | 'credits';

const STORAGE_KEYS = {
  USER: 'al_2026_user_v2',
  SUBJECTS_PREFIX: 'al_2026_subjects_v2_',
  GOALS: 'al_2026_goals_v2'
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [currentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  // Calculate Overall Progress (Batch Index)
  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  // Sync Load
  useEffect(() => {
    const initApp = async () => {
      try {
        const savedUserJson = localStorage.getItem(STORAGE_KEYS.USER);
        if (savedUserJson) {
          const parsedUser = JSON.parse(savedUserJson) as User;
          setUser(parsedUser);

          const savedSubjectsJson = localStorage.getItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${parsedUser.streamId}`);
          if (savedSubjectsJson) {
            setSubjects(JSON.parse(savedSubjectsJson));
          }
        }

        const savedGoals = localStorage.getItem(STORAGE_KEYS.GOALS);
        if (savedGoals) setGoals(JSON.parse(savedGoals));

      } catch (err) {
        console.error("Initialization Error:", err);
      } finally {
        setIsAuthLoading(false);
      }
    };
    initApp();
  }, []);

  // Persist Subjects
  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  const handleLogin = (name: string, remember: boolean, streamId: string, selectedSubjects: Subject[]) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    setSubjects(selectedSubjects);
    if (remember) {
      localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(newUser));
      localStorage.setItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${streamId}`, JSON.stringify(selectedSubjects));
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem(STORAGE_KEYS.USER);
    setSubjects([]);
    setActiveView('dashboard');
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    if (isLoadingNews) return;
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0 && !news) {
      refreshNews();
    }
  }, [user, timeLeft.days, news]);

  if (isAuthLoading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center gap-4">
      <div className="w-12 h-12 rounded-2xl border-4 border-blue-500/10 border-t-blue-500 animate-spin" />
      <span className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-500/60">Initializing Command Hub</span>
    </div>
  );

  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="flex flex-col gap-10 md:gap-16 animate-reveal max-w-tv mx-auto w-full">
            {/* Redesigned Command Hero Section */}
            <section className="relative w-full overflow-hidden rounded-[3rem] p-8 md:p-12 lg:p-20 glass-card border-white/5 bg-gradient-to-br from-slate-900/50 via-slate-900/80 to-blue-950/20 shadow-2xl group">
              <div className="absolute top-0 right-0 w-2/3 h-full bg-blue-600/[0.03] blur-[150px] -z-10 animate-pulse" />

              <div className="flex flex-col lg:flex-row items-center justify-between gap-12 relative z-10">
                <div className="text-center lg:text-left space-y-4 max-w-2xl">
                  <div className="inline-flex items-center gap-3 px-4 py-2 rounded-full bg-blue-500/10 border border-blue-500/20 mb-2">
                    <span className="w-2 h-2 rounded-full bg-blue-400 animate-pulse" />
                    <span className="text-[10px] font-black uppercase tracking-widest text-blue-400">Sri Lanka A/L • Batch of 2026</span>
                  </div>
                  <h1 className="text-4xl md:text-6xl lg:text-7xl font-black font-outfit tracking-tighter leading-tight text-white">
                    Mastery is the <br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-400 via-indigo-400 to-purple-400">Only Goal.</span>
                  </h1>

                  {/* Batch Progress Integrated into Hero */}
                  <div className="pt-6 space-y-4 max-w-sm mx-auto lg:mx-0">
                    <div className="flex justify-between items-end mb-1">
                      <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Global Batch Progress</span>
                      <span className="text-blue-400 font-black text-2xl font-mono-tech leading-none">~{batchIndex}%</span>
                    </div>
                    <div className="w-full bg-black/40 rounded-full h-3 p-0.5 border border-white/5 backdrop-blur-md">
                      <div className="bg-gradient-to-r from-blue-600 via-blue-400 to-indigo-500 h-full rounded-full transition-all duration-[2s]" style={{ width: `${batchIndex}%` }} />
                    </div>
                  </div>
                </div>

                <div className="w-full lg:w-auto flex-shrink-0 scale-90 lg:scale-100 transition-transform">
                  <CountdownCard timeLeft={timeLeft} />
                </div>
              </div>
            </section>

            {/* Main Content Grid - Rebalanced */}
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-12 w-full">
              {/* Left Column - Real-time Data */}
              <div className="lg:col-span-7 space-y-10">
                <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
                <StudyGoals />
              </div>

              {/* Right Column - Strategic Assets */}
              <div className="lg:col-span-5 space-y-10">
                <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
                <div className="sticky top-32">
                  <AIChatBuddy />
                </div>
              </div>
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 animate-reveal max-w-tv mx-auto w-full">
            <div className="lg:col-span-8">
              <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
            </div>
            <div className="lg:col-span-4 space-y-8">
              <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
              <AIChatBuddy />
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-10 animate-reveal max-w-tv mx-auto w-full">
            <FocusTimer />
