      case 'timetable':
        return <div className="max-w-tv mx-auto"><TimetablePage subjects={subjects} /></div>;
      case 'stats':
        return <div className="max-w-tv mx-auto"><OverallStats subjects={subjects} goals={goals} /></div>;
      case 'credits':
