      case 'chat':
        return (
          <div className="max-w-4xl mx-auto w-full h-[80vh] flex flex-col p-2">
            <AIChatBuddy />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-48 selection:bg-blue-500/30">
      {/* Dynamic Navigation */}
      <nav className="px-6 py-8 md:px-12 md:py-10 flex justify-between items-center max-w-tv mx-auto sticky top-0 z-[100] backdrop-blur-2xl bg-slate-950/20 border-b border-white/[0.03]">
        <div className="flex items-center gap-4 cursor-pointer group" onClick={() => setActiveView('dashboard')}>
          <div className="w-12 h-12 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl flex items-center justify-center font-black text-2xl shadow-xl transform group-hover:rotate-0 transition-transform rotate-6 text-white">A</div>
