      <main className="px-6 md:px-12 pt-10">
        {renderView()}
      </main>

      {/* Modern Fixed Navigation */}
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[100] w-[92%] max-w-4xl">
        <div className="glass-card rounded-[3rem] p-2.5 flex items-center justify-between border-white/10 shadow-[0_40px_100px_rgba(0,0,0,0.6)] bg-slate-950/80 backdrop-blur-3xl">
          {[
            { id: 'dashboard', label: 'Dash', icon: 'M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z' },
            { id: 'curriculum', label: 'Syllabus', icon: 'M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z' },
            { id: 'timetable', label: 'Plan', icon: 'M6 2a1 1 0 00-1 1v1H4a2 2 0 00-2 2v10a2 2 0 002 2h12a2 2 0 002-2V6a2 2 0 00-2-2h-1V3a1 1 0 10-2 0v1H7V3a1 1 0 00-1-1zm0 5a1 1 0 000 2h8a1 1 0 100-2H6z' },
            { id: 'stats', label: 'Stats', icon: 'M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z' },
            { id: 'tools', label: 'Tools', icon: 'M5 3a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V5a2 2 0 00-2-2H5zM5 11a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2v-2a2 2 0 00-2-2H5zM11 5a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2zM11 13a2 2 0 00-2 2v2a2 2 0 002 2h2a2 2 0 002-2v-2a2 2 0 00-2-2h-2z' }
          ].map((nav) => (
            <button 
              key={nav.id}
              onClick={() => setActiveView(nav.id as View)}
              className={`flex-1 py-4 md:py-5 rounded-[2.5rem] flex flex-col items-center gap-1.5 transition-all duration-500 group ${activeView === nav.id ? 'bg-blue-600 text-white shadow-[0_10px_40px_rgba(37,99,235,0.4)] scale-105' : 'text-slate-500 hover:text-slate-200 hover:bg-white/5'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" viewBox="0 0 20 20" fill="currentColor">
                <path d={nav.icon} />
              </svg>
              <span className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.1em]">{nav.label}</span>
            </button>
          ))}
        </div>
      </div>

      <footer className="mt-40 py-16 text-center opacity-20 hover:opacity-100 transition-opacity duration-1000">
        <p className="text-[10px] font-black uppercase tracking-[0.5em] text-slate-500 leading-loose">
          Encrypted Data Stream • Success is a System • GCE A/L Official 2026 Portal
        </p>
      </footer>
    </div>
  );
};

