import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithStudyBuddy } from '../services/geminiService';

const STORAGE_KEY = 'al_2026_chat_history_v2';

const AIChatBuddy: React.FC = () => {
  // Initialize messages from localStorage
  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to load chat history", e);
      return [];
    }
  });

  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Persist messages to localStorage whenever they change
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(messages));
  }, [messages]);

  useEffect(() => {
    if (error) {
      const timer = setTimeout(() => setError(null), 8000);
      return () => clearTimeout(timer);
    }
  }, [error]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || isTyping) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    const updatedMessages = [...messages, userMsg];
    setMessages(updatedMessages);

    const currentInput = input;
    setInput('');
    setIsTyping(true);
    setError(null);

    try {
      const response = await chatWithStudyBuddy(updatedMessages, currentInput);
      const botMsg: ChatMessage = { role: 'model', text: response, timestamp: Date.now() };
      setMessages(prev => [...prev, botMsg]);
    } catch (err: any) {
      setError("Strategic Advisor busy. Please rephrase or wait.");
      console.error(err);
    } finally {
      setIsTyping(false);
    }
  };

  const clearChat = () => {
    if (window.confirm("Clear all strategic consultation history?")) {
      setMessages([]);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="glass-card rounded-[3rem] p-6 md:p-12 border-indigo-500/10 flex flex-col h-full relative shadow-[0_50px_100px_-20px_rgba(0,0,0,0.8)] overflow-hidden">
      {/* Immersive Background Element */}
      <div className="absolute top-[-20%] left-[-10%] w-[60%] h-[60%] bg-indigo-600/5 blur-[120px] rounded-full pointer-events-none" />

      {error && (
        <div className="absolute top-6 left-6 right-6 z-50 animate-reveal">
          <div className="bg-red-500/10 backdrop-blur-2xl border border-red-500/20 rounded-2xl p-4 flex items-center justify-between shadow-2xl">
            <span className="text-xs font-bold text-red-200">⚠️ {error}</span>
            <button onClick={() => setError(null)} className="text-red-400 p-2">✕</button>
          </div>
        </div>
      )}

      {/* Standalone Header for Professional Feel */}
      <header className="flex items-center justify-between mb-8 md:mb-12 shrink-0 relative z-10">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 rounded-[1.8rem] bg-gradient-to-br from-indigo-600 to-purple-700 flex items-center justify-center text-white shadow-2xl transform rotate-3">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" viewBox="0 0 20 20" fill="currentColor">
              <path d="M10.394 2.827c.079-.441.51-.783.976-.783h2.26c.466 0 .897.342.976.783l.267 1.488c.113.628.761 1.018 1.343.812l1.396-.496c.44-.156.963.033 1.206.442l1.13 1.957c.243.41.13 1.013-.255 1.325l-1.22.993c-.482.392-.482 1.222 0 1.614l1.22.993c.385.312.498.915.255 1.325l-1.13 1.957c-.243.41-.766.598-1.206.442l-1.396-.496c-.582-.206-1.23.184-1.343.812l-.267 1.488c-.079.441-.51.783-.976.783h-2.26c-.466 0-.897-.342-.976-.783l-.267-1.488c-.113-.628-.761-1.018-1.343-.812l-1.396.496c-.44.156-.963-.033-1.206-.442l-1.13-1.957c-.243-.41-.13-1.013.255-1.325l1.22-.993c.482-.392.482-1.222 0-1.614l-1.22-.993c-.385-.312-.498-.915-.255-1.325l1.13-1.957c.243-.41.766-.598 1.206-.442l1.396.496c.582.206 1.23-.184 1.343-.812l.267-1.488z" />
            </svg>
          </div>
          <div>
            <h1 className="font-black text-2xl md:text-3xl font-outfit text-white leading-none tracking-tight">AI Strategy Buddy</h1>
            <div className="flex items-center gap-2 mt-2">
               <span className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em]">Senior Academic Consultant</span>
               <div className={`w-2 h-2 rounded-full ${isTyping ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'} shadow-[0_0_10px_rgba(16,185,129,0.4)]`} />
            </div>
          </div>
        </div>
        <div className="flex items-center gap-4">
          {messages.length > 0 && (
            <button 
