              className="text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-red-400 transition-colors px-4 py-2 rounded-xl bg-white/5 border border-white/5"
            >
              Clear Log
            </button>
          )}
          <div className="hidden sm:flex flex-col text-right">
            <span className="text-[10px] font-black uppercase tracking-widest text-slate-500">Service Status</span>
            <span className="text-xs font-bold text-slate-300">Operational • History Saved</span>
          </div>
        </div>
      </header>

      {/* Message Area */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto pr-2 md:pr-4 custom-scrollbar space-y-6 md:space-y-8 mb-8 relative z-10">
        {messages.length === 0 && (
          <div className="h-full flex flex-col items-center justify-center text-center px-6 animate-reveal">
            <div className="w-24 h-24 md:w-32 md:h-32 bg-indigo-500/5 rounded-[2.5rem] flex items-center justify-center text-5xl md:text-6xl mb-10 border border-indigo-500/10 grayscale opacity-40">🧠</div>
