          </div>
        ))}

        {isTyping && (
          <div className="flex justify-start animate-reveal">
            <div className="bg-slate-900/80 p-5 rounded-[1.5rem] rounded-tl-none flex gap-1.5 items-center border border-white/5 backdrop-blur-md shadow-lg">
