import React, { useMemo } from 'react';
import { Subject, Goal } from '../types';

interface OverallStatsProps {
  subjects: Subject[];
  goals: Goal[];
}

const OverallStats: React.FC<OverallStatsProps> = ({ subjects, goals }) => {
  const stats = useMemo(() => {
    let totalUnits = 0;
    let completedUnits = 0;

    subjects.forEach(s => {
      totalUnits += s.units.length;
      completedUnits += s.units.filter(u => u.completed).length;
    });

    const masteryPercentage = totalUnits > 0 ? Math.round((completedUnits / totalUnits) * 100) : 0;
    const goalsCompleted = goals.filter(g => g.completed).length;

    // Calculate readiness level
    let readiness = "Foundation Stage";
    let readinessColor = "text-blue-400";
    if (masteryPercentage > 30) { readiness = "Operational"; readinessColor = "text-indigo-400"; }
    if (masteryPercentage > 60) { readiness = "Advanced Mastery"; readinessColor = "text-purple-400"; }
    if (masteryPercentage > 85) { readiness = "Strategic Readiness"; readinessColor = "text-emerald-400"; }

    return {
      masteryPercentage,
      totalUnits,
      completedUnits,
      goalsCompleted,
      readiness,
      readinessColor
    };
  }, [subjects, goals]);

  const strokeDasharray = 2 * Math.PI * 45;
  const strokeDashoffset = strokeDasharray - (stats.masteryPercentage / 100) * strokeDasharray;

  return (
    <div className="glass-card rounded-[3rem] p-8 md:p-12 border-blue-500/10 w-full animate-reveal">
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">

        {/* Visual Mastery Ring */}
        <div className="flex flex-col items-center justify-center relative">
          <svg className="w-64 h-64 transform -rotate-90">
            {/* Background Circle */}
            <circle
              cx="128"
              cy="128"
              r="110"
              stroke="currentColor"
              strokeWidth="12"
              fill="transparent"
              className="text-slate-900"
            />
            {/* Progress Circle */}
            <circle
              cx="128"
              cy="128"
              r="110"
              stroke="currentColor"
              strokeWidth="12"
              strokeDasharray={2 * Math.PI * 110}
              strokeDashoffset={2 * Math.PI * 110 - (stats.masteryPercentage / 100) * 2 * Math.PI * 110}
              strokeLinecap="round"
              fill="transparent"
              className="text-blue-600 transition-all duration-[2s] ease-out shadow-2xl"
              style={{ filter: 'drop-shadow(0 0 12px rgba(37, 99, 235, 0.4))' }}
            />
          </svg>
          <div className="absolute flex flex-col items-center justify-center text-center">
            <span className="text-6xl font-black font-outfit text-white tracking-tighter">
              {stats.masteryPercentage}<span className="text-2xl text-blue-500">%</span>
            </span>
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500 mt-2">Global Mastery</span>
          </div>
        </div>

        {/* Breakdown Stats */}
        <div className="space-y-8">
          <div>
            <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mb-2">Readiness Status</h3>
            <p className={`text-3xl md:text-4xl font-black font-outfit tracking-tight ${stats.readinessColor}`}>
              {stats.readiness}
            </p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="bg-slate-900/40 p-5 rounded-3xl border border-white/5">
              <span className="block text-[9px] font-black uppercase tracking-widest text-slate-500 mb-1">Syllabus Progress</span>
              <span className="text-xl font-black text-white">{stats.completedUnits} / {stats.totalUnits}</span>
