import React, { useMemo } from 'react';
import { Subject, Goal } from '../types';

interface ThreeARoadmapProps {
  subjects: Subject[];
  goals: Goal[];
}

const ThreeARoadmap: React.FC<ThreeARoadmapProps> = ({ subjects, goals }) => {
  const roadmapData = useMemo(() => {
    // Only track the top 3 subjects
    const topSubjects = subjects.slice(0, 3);
    const goalBoost = goals.length > 0 ? (goals.filter(g => g.completed).length / goals.length) * 10 : 0;

    return topSubjects.map(s => {
      const confidence = Math.min(100, s.progress + goalBoost);
      return {
        id: s.id,
        name: s.name,
        progress: s.progress,
        confidence,
        isReady: s.progress >= 75,
        color: s.color.replace('bg-', 'text-')
      };
    });
  }, [subjects, goals]);

  return (
    <div className="w-full space-y-8 animate-reveal delay-300">
      <div className="flex items-center justify-between px-2">
        <div>
          <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mb-1">Strategic Outlook</h3>
          <h2 className="text-xl md:text-2xl font-black font-outfit text-white">The 3A Roadmap</h2>
        </div>
        <div className="text-right">
          <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 block">Probability Index</span>
          <span className="text-sm font-black text-indigo-400">
            {roadmapData.length > 0 ? Math.round(roadmapData.reduce((acc, val) => acc + val.confidence, 0) / roadmapData.length) : 0}% High
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {roadmapData.map((data, idx) => (
          <div key={data.id} className="glass-card rounded-[2.5rem] p-6 border-white/5 relative overflow-hidden group">
            {/* Background Accent */}
            <div className={`absolute -right-10 -bottom-10 w-32 h-32 rounded-full blur-[60px] opacity-10 transition-all duration-700 group-hover:opacity-20 ${data.color.replace('text-', 'bg-')}`} />

            <div className="relative z-10 flex flex-col items-center text-center">
              {/* Grade Indicator */}
              <div className="relative w-24 h-24 mb-4">
                <svg className="w-full h-full transform -rotate-90">
                  <circle
                    cx="48"
                    cy="48"
                    r="44"
                    stroke="currentColor"
                    strokeWidth="4"
                    fill="transparent"
                    className="text-slate-900"
                  />
                  <circle
                    cx="48"
                    cy="48"
                    r="44"
                    stroke="currentColor"
                    strokeWidth="6"
                    strokeDasharray={2 * Math.PI * 44}
                    strokeDashoffset={2 * Math.PI * 44 - (data.progress / 100) * 2 * Math.PI * 44}
                    strokeLinecap="round"
                    fill="transparent"
                    className={`${data.isReady ? 'text-amber-400' : 'text-blue-500'} transition-all duration-1000 ease-out`}
                  />
                </svg>
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className={`text-4xl font-black font-outfit transition-all duration-500 ${data.isReady ? 'text-amber-400 drop-shadow-[0_0_12px_rgba(251,191,36,0.6)] scale-110' : 'text-slate-700'}`}>
                    A
                  </span>
                </div>
              </div>

              <span className="text-[10px] font-black uppercase tracking-widest text-slate-500 mb-1">{data.name}</span>
              <div className="flex items-center gap-2">
                <div className={`h-1.5 w-1.5 rounded-full ${data.isReady ? 'bg-emerald-500 animate-pulse' : 'bg-slate-700'}`} />
                <span className={`text-xs font-bold ${data.isReady ? 'text-white' : 'text-slate-500'}`}>
                  {data.isReady ? 'Strategic Mastery' : `${data.progress}% Mastery`}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Goal Multiplier Status */}
      <div className="bg-slate-900/40 p-5 rounded-3xl border border-white/5 flex items-center justify-between gap-6">
        <div className="flex items-center gap-4">
          <div className="w-10 h-10 rounded-2xl bg-indigo-600/10 flex items-center justify-center text-indigo-400 text-lg">🎯</div>
          <div>
            <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 block">Goal Boost Applied</span>
            <span className="text-xs font-bold text-slate-300">
              {goals.filter(g => g.completed).length} / {goals.length} Strategic Targets Met
            </span>
          </div>
        </div>
        <div className="flex-1 max-w-xs bg-slate-950/60 rounded-full h-1.5 overflow-hidden">
          <div 
            className="bg-indigo-500 h-full transition-all duration-1000 ease-out shadow-[0_0_10px_rgba(99,102,241,0.5)]" 
            style={{ width: `${goals.length > 0 ? (goals.filter(g => g.completed).length / goals.length) * 100 : 0}%` }}
          />
        </div>
      </div>
    </div>
  );
};

