import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { EXAM_DATE, AL_STREAMS } from './constants';
import { TimeLeft, Subject, User, Goal } from './types';
import CountdownCard from './components/CountdownCard';
import SubjectTracker from './components/SubjectTracker';
import StudyGoals from './components/StudyGoals';
import ExamNews from './components/ExamNews';
import LoginPage from './components/LoginPage';
import FocusTimer from './components/FocusTimer';
import ResourceVault from './components/ResourceVault';
import AIChatBuddy from './components/AIChatBuddy';
import CurriculumHub from './components/CurriculumHub';
import CreditsPage from './components/CreditsPage';
import TimetablePage from './components/TimetablePage';
import OverallStats from './components/OverallStats';
import ThreeARoadmap from './components/ThreeARoadmap';
import { fetchLatestExamNews, ExamNews as ExamNewsType } from './services/geminiService';

type View = 'dashboard' | 'curriculum' | 'tools' | 'chat' | 'timetable' | 'stats' | 'credits';

const STORAGE_KEYS = {
  USER: 'al_2026_user_v2',
  SUBJECTS_PREFIX: 'al_2026_subjects_v2_',
  GOALS: 'al_2026_goals' // Sync with StudyGoals storage key
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [activeView, setActiveView] = useState<View>('dashboard');
  const [currentExamDate] = useState<Date>(EXAM_DATE);
  const [timeLeft, setTimeLeft] = useState<TimeLeft>({ days: 0, hours: 0, minutes: 0, seconds: 0 });
  const [news, setNews] = useState<ExamNewsType | null>(null);
  const [lastNewsUpdate, setLastNewsUpdate] = useState<string | null>(null);
  const [isLoadingNews, setIsLoadingNews] = useState(false);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  const batchIndex = useMemo(() => {
    if (subjects.length === 0) return 0;
    const total = subjects.reduce((acc, s) => acc + s.progress, 0);
    return Math.round(total / subjects.length);
  }, [subjects]);

  useEffect(() => {
    const initApp = async () => {
      try {
        const savedUserJson = localStorage.getItem(STORAGE_KEYS.USER);
        if (savedUserJson) {
          const parsedUser = JSON.parse(savedUserJson) as User;
          setUser(parsedUser);
          const savedSubjectsJson = localStorage.getItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${parsedUser.streamId}`);
          if (savedSubjectsJson) setSubjects(JSON.parse(savedSubjectsJson));
        }
        const savedGoals = localStorage.getItem(STORAGE_KEYS.GOALS);
        if (savedGoals) setGoals(JSON.parse(savedGoals));
      } catch (err) {
        console.error("Initialization Error:", err);
      } finally {
        setIsAuthLoading(false);
      }
    };
    initApp();
  }, []);

  useEffect(() => {
    if (user && subjects.length > 0) {
      localStorage.setItem(`${STORAGE_KEYS.SUBJECTS_PREFIX}${user.streamId}`, JSON.stringify(subjects));
    }
  }, [subjects, user]);

  // Persist goals whenever they change
  useEffect(() => {
    if (goals.length >= 0) {
      localStorage.setItem(STORAGE_KEYS.GOALS, JSON.stringify(goals));
    }
  }, [goals]);

  const handleLogin = (name: string, remember: boolean, streamId: string, chosenSubjects: Subject[]) => {
    const newUser = { name, isLoggedIn: true, streamId };
    setUser(newUser);
    setSubjects(chosenSubjects);
    if (remember) {
      localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(newUser));
    }
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem(STORAGE_KEYS.USER);
    setSubjects([]);
    setGoals([]);
    setActiveView('dashboard');
  };

  const toggleUnit = (subjectId: string, unitId: string) => {
    setSubjects(prev => prev.map(s => {
      if (s.id === subjectId) {
        const newUnits = s.units.map(u => 
          u.id === unitId ? { ...u, completed: !u.completed } : u
        );
        const completedCount = newUnits.filter(u => u.completed).length;
        const newProgress = Math.round((completedCount / newUnits.length) * 100);
        return { ...s, units: newUnits, progress: newProgress };
      }
      return s;
    }));
  };

  const togglePriority = (subjectId: string) => {
    setSubjects(prev => prev.map(s => 
      s.id === subjectId ? { ...s, isPrioritized: !s.isPrioritized } : s
    ));
  };

  const calculateTimeLeft = useCallback(() => {
    const now = new Date();
    const difference = currentExamDate.getTime() - now.getTime();
    if (difference > 0) {
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
        minutes: Math.floor((difference / 1000 / 60) % 60),
        seconds: Math.floor((difference / 1000) % 60)
      });
    } else {
      setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
    }
  }, [currentExamDate]);

  useEffect(() => {
    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);
    return () => clearInterval(timer);
  }, [calculateTimeLeft]);

  const refreshNews = async () => {
    if (isLoadingNews) return;
    setIsLoadingNews(true);
    try {
      const newsResult = await fetchLatestExamNews();
      setNews(newsResult);
      setLastNewsUpdate(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }));
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoadingNews(false);
    }
  };

  useEffect(() => {
    if (user && timeLeft.days > 0 && !news) {
      refreshNews();
    }
  }, [user, timeLeft.days, news]);

  if (isAuthLoading) return (
    <div className="min-h-screen bg-slate-950 flex flex-col items-center justify-center gap-4">
      <div className="w-12 h-12 rounded-2xl border-4 border-blue-500/10 border-t-blue-500 animate-spin" />
      <span className="text-[10px] font-black uppercase tracking-[0.3em] text-blue-500/60">Launching Dashboard...</span>
    </div>
  );

  if (!user) return <LoginPage onLogin={handleLogin} />;

  const renderView = () => {
    switch(activeView) {
      case 'dashboard':
        return (
          <div className="flex flex-col gap-10 md:gap-16 lg:gap-20 animate-reveal max-w-tv mx-auto w-full">
            <section className="relative w-full rounded-[2.5rem] md:rounded-[4rem] p-6 md:p-16 lg:p-24 overflow-hidden border border-white/[0.05] bg-gradient-to-br from-slate-900/60 via-slate-950/80 to-blue-950/20">
              <div className="absolute top-0 right-0 w-full h-full bg-blue-500/[0.03] blur-[160px] -z-10" />
              <div className="flex flex-col items-center justify-center text-center space-y-10 md:space-y-16 relative z-10">
                <div className="space-y-4 md:space-y-6">
                  <div className="inline-flex items-center gap-3 px-4 py-1.5 md:py-2.5 rounded-full bg-white/5 backdrop-blur-md border border-white/10 mb-2">
                    <span className="w-2 h-2 rounded-full bg-blue-500 animate-pulse" />
                    <span className="text-[8px] md:text-[10px] font-black uppercase tracking-[0.3em] text-blue-400">Class of 2026 Portal</span>
                  </div>
                  <h1 className="text-7xl md:text-8xl lg:text-[10rem] font-black font-outfit tracking-tighter leading-[0.8] text-white animate-float select-none">
                    3A's <br/>
                    <span className="text-transparent bg-clip-text bg-gradient-to-b from-amber-200 via-yellow-400 to-amber-700 drop-shadow-[0_0_30px_rgba(251,191,36,0.4)]">
                      On the Way.
                    </span>
                  </h1>
                </div>
                <div className="w-full transform transition-all duration-700">
                  <CountdownCard timeLeft={timeLeft} />
                </div>
                <div className="w-full max-w-3xl pt-4">
                  <div className="flex justify-between items-end mb-3 md:mb-4 px-2">
                    <span className="text-[10px] md:text-[12px] text-slate-500 font-black uppercase tracking-[0.2em]">Global Mastery</span>
                    <span className="text-white font-black text-2xl md:text-4xl font-mono-tech tracking-tighter">{batchIndex}%</span>
                  </div>
                  <div className="w-full bg-slate-950/60 rounded-full h-2 md:h-2.5 p-0.5 border border-white/[0.08]">
                    <div 
                      className="bg-gradient-to-r from-blue-600 via-indigo-500 to-purple-600 h-full rounded-full transition-all duration-[2.5s] shadow-[0_0_20px_rgba(59,130,246,0.3)]" 
                      style={{ width: `${batchIndex}%` }} 
                    />
                  </div>
                </div>
              </div>
            </section>

            {/* Strategic 3A Outlook Section */}
            <ThreeARoadmap subjects={subjects} goals={goals} />

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 md:gap-16 w-full px-2 md:px-0">
              <div className="lg:col-span-7 space-y-10 md:space-y-16">
                <div className="space-y-4">
                  <h2 className="text-xl md:text-2xl font-black font-outfit text-white tracking-tight flex items-center gap-3">
                    <span className="w-8 h-8 rounded-xl bg-blue-600/10 flex items-center justify-center text-blue-500 text-sm">📡</span>
                    Government Intelligence
                  </h2>
                  <ExamNews news={news} isLoading={isLoadingNews} onRefresh={refreshNews} lastUpdated={lastNewsUpdate} />
                </div>
              </div>
              <div className="lg:col-span-5 space-y-10 md:space-y-16">
                <div className="space-y-4">
                  <h2 className="text-xl md:text-2xl font-black font-outfit text-white tracking-tight flex items-center gap-3">
                    <span className="w-8 h-8 rounded-xl bg-purple-600/10 flex items-center justify-center text-purple-500 text-sm">📊</span>
                    Performance Stats
                  </h2>
                  <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
                </div>
              </div>
            </div>
          </div>
        );
      case 'curriculum':
        return (
          <div className="flex flex-col gap-10 animate-reveal max-w-tv mx-auto w-full">
            <header className="mb-4">
              <h1 className="text-3xl md:text-5xl font-black font-outfit text-white">Study & Progression</h1>
              <p className="text-slate-500 text-[10px] md:text-sm uppercase tracking-widest mt-1">Check off units and manage active goals.</p>
            </header>
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
              <div className="lg:col-span-8">
                <CurriculumHub subjects={subjects} toggleUnit={toggleUnit} />
              </div>
              <div className="lg:col-span-4 space-y-8">
                <div className="space-y-4">
                  <h2 className="text-xl font-black font-outfit text-white tracking-tight px-2 flex items-center gap-3">
                    <span className="w-7 h-7 rounded-lg bg-emerald-600/10 flex items-center justify-center text-emerald-500 text-xs">🎯</span>
                    Active Goals
                  </h2>
                  <StudyGoals goals={goals} setGoals={setGoals} />
                </div>
                <div className="space-y-4">
                  <h2 className="text-xl font-black font-outfit text-white tracking-tight px-2 flex items-center gap-3">
                    <span className="w-7 h-7 rounded-lg bg-purple-600/10 flex items-center justify-center text-purple-500 text-xs">📊</span>
                    Subject Mastery
                  </h2>
                  <SubjectTracker subjects={subjects} onTogglePriority={togglePriority} />
                </div>
              </div>
            </div>
          </div>
        );
      case 'tools':
        return (
          <div className="flex flex-col gap-10 animate-reveal max-w-tv mx-auto w-full">
             <header className="mb-4">
              <h1 className="text-3xl md:text-5xl font-black font-outfit text-white">Arsenal</h1>
              <p className="text-slate-500 text-[10px] md:text-sm uppercase tracking-widest mt-1">Deep focus and academic tools.</p>
            </header>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <FocusTimer />
              <ResourceVault />
            </div>
          </div>
        );
      case 'timetable':
        return <div className="max-w-tv mx-auto w-full"><TimetablePage subjects={subjects} /></div>;
      case 'stats':
        return (
          <div className="max-w-tv mx-auto w-full space-y-8 animate-reveal">
            <header className="mb-4">
              <h1 className="text-3xl md:text-5xl font-black font-outfit text-white">Global Readiness</h1>
              <p className="text-slate-500 text-[10px] md:text-sm uppercase tracking-widest mt-1">Comprehensive performance analytics.</p>
            </header>
            <OverallStats subjects={subjects} goals={goals} />
          </div>
        );
      case 'credits':
        return <div className="max-w-tv mx-auto w-full"><CreditsPage /></div>;
      case 'chat':
        return (
          <div className="max-w-6xl mx-auto w-full h-[80vh] min-h-[500px] animate-reveal">
            <AIChatBuddy />
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen pb-40 md:pb-48 selection:bg-blue-500/30">
      <nav className="px-4 py-6 md:px-12 md:py-12 flex justify-between items-center max-w-tv mx-auto sticky top-0 z-[100] backdrop-blur-3xl bg-slate-950/40 border-b border-white/[0.03]">
        <div className="flex items-center gap-4 md:gap-6 cursor-pointer group" onClick={() => setActiveView('dashboard')}>
          <div className="w-10 h-10 md:w-14 md:h-14 bg-gradient-to-br from-blue-600 to-indigo-800 rounded-xl md:rounded-[1.4rem] flex items-center justify-center font-black text-xl md:text-3xl shadow-xl text-white transform group-hover:rotate-0 transition-all rotate-6">A</div>
          <div className="flex flex-col">
            <span className="text-lg md:text-2xl font-black font-outfit uppercase leading-none text-white">Success Hub</span>
            <span className="text-[7px] md:text-[9px] text-blue-500 font-black tracking-[0.4em] uppercase mt-1">Batch of 2026</span>
          </div>
        </div>
        <div className="flex items-center gap-4 md:gap-10">
          <div className="text-right hidden sm:block">
            <p className="text-[8px] md:text-[10px] font-black uppercase tracking-widest text-slate-500">Candidate</p>
            <p className="text-sm md:text-base font-black text-white tracking-tight">{user.name}</p>
          </div>
          <button onClick={handleLogout} className="p-3 md:p-4 rounded-xl md:rounded-2xl bg-white/[0.04] text-slate-500 hover:text-red-400 transition-all border border-white/[0.08]">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
            </svg>
          </button>
        </div>
      </nav>

      <main className="px-4 md:px-12 pt-8 md:pt-12">
        {renderView()}
      </main>

      <div className="fixed bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 z-[100] w-[95%] max-w-4xl">
        <div className="glass-card rounded-full p-1.5 md:p-2.5 flex items-center justify-between border-white/10 shadow-[0_40px_100px_rgba(0,0,0,0.8)] bg-slate-950/90 backdrop-blur-3xl">
          {[
            { id: 'dashboard', label: 'Dash', icon: 'M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a1 1 0 001 1h2a1 1 0 001-1v-2a1 1 0 011-1h2a1 1 0 011 1v2a1 1 0 001 1h2a1 1 0 001-1v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z' },
            { id: 'curriculum', label: 'Syllabus', icon: 'M9 4.804A7.968 7.968 0 005.5 4c-1.255 0-2.443.29-3.5.804v10A7.969 7.969 0 015.5 14c1.669 0 3.218.51 4.5 1.385A7.962 7.962 0 0114.5 14c1.255 0 2.443.29 3.5.804v-10A7.968 7.968 0 0014.5 4c-1.255 0-2.443.29-3.5.804V12a1 1 0 11-2 0V4.804z' },
