import React, { useState, useMemo } from 'react';
import { AL_STREAMS } from '../constants';
import { Subject } from '../types';

interface LoginPageProps {
  onLogin: (name: string, remember: boolean, streamId: string, chosenSubjects: Subject[]) => void;
}

const LoginPage: React.FC<LoginPageProps> = ({ onLogin }) => {
  const [name, setName] = useState('');
  const [streamId, setStreamId] = useState(AL_STREAMS[0].id);
  const [selectedSubjectIds, setSelectedSubjectIds] = useState<string[]>([]);
  const [remember, setRemember] = useState(true);
  const [error, setError] = useState('');

  const currentStream = useMemo(() => 
    AL_STREAMS.find(s => s.id === streamId) || AL_STREAMS[0]
  , [streamId]);

  const toggleSubject = (id: string) => {
    setError('');
    setSelectedSubjectIds(prev => {
      if (prev.includes(id)) {
        return prev.filter(sid => sid !== id);
      }
      if (prev.length >= 3) return prev;
      return [...prev, id];
    });
  };

  const handleStreamChange = (id: string) => {
    setStreamId(id);
    setSelectedSubjectIds([]); // Reset selection when stream changes
    setError('');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) {
      setError('Please enter your name');
      return;
    }
    if (selectedSubjectIds.length !== 3) {
      setError('Please select exactly 3 core subjects');
      return;
    }

    const chosenSubjects = currentStream.subjects.filter(s => 
      selectedSubjectIds.includes(s.id)
    );

    onLogin(name, remember, streamId, chosenSubjects);
  };

  return (
    <div className="min-h-screen flex items-center justify-center py-12 px-6 relative overflow-hidden bg-slate-950">
      <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-600/10 blur-[120px] rounded-full animate-float" />
      <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600/10 blur-[120px] rounded-full animate-float" style={{ animationDelay: '3s' }} />

      <div className="glass-card w-full max-w-4xl p-8 md:p-12 rounded-[2.5rem] relative z-10 animate-reveal">
        <div className="text-center mb-10">
          <div className="w-16 h-16 md:w-20 md:h-20 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl flex items-center justify-center font-black text-3xl md:text-4xl shadow-2xl shadow-blue-900/40 text-white mx-auto mb-6 transform rotate-6 hover:rotate-0 transition-transform duration-500">A</div>
          <h1 className="text-3xl md:text-4xl font-black font-outfit text-white tracking-tighter">SUCCESS HUB</h1>
          <p className="text-slate-400 text-[10px] md:text-sm font-medium mt-2 uppercase tracking-[0.3em]">Batch of 2026 Registry</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-12">
          {/* Section 1: Name */}
          <div className="max-w-md mx-auto">
            <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-3 ml-1">Candidate Identity</label>
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Your Full Name..."
              className="w-full bg-slate-900/50 border border-slate-700/50 rounded-2xl px-5 py-4 text-white placeholder-slate-600 focus:outline-none focus:border-blue-500 transition-all font-medium text-lg"
            />
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
            {/* Section 2: Stream Selection */}
            <div>
              <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-4 ml-1">Academic Stream</label>
              <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                {AL_STREAMS.map(stream => {
                  const isSelected = streamId === stream.id;
                  return (
                    <button
                      key={stream.id}
                      type="button"
                      onClick={() => handleStreamChange(stream.id)}
                      className={`w-full text-left p-4 rounded-2xl border transition-all duration-300 relative group overflow-hidden ${
                        isSelected 
                          ? 'bg-blue-600/10 border-blue-500 shadow-[0_0_15px_rgba(59,130,246,0.1)]' 
                          : 'bg-slate-900/20 border-slate-800 hover:border-slate-700'
                      }`}
                    >
                      <h3 className={`text-sm font-black transition-colors ${isSelected ? 'text-blue-400' : 'text-slate-400'}`}>
                        {stream.name}
                      </h3>
                      {isSelected && (
                        <div className="absolute top-1/2 -translate-y-1/2 right-4 w-2 h-2 rounded-full bg-blue-500 shadow-[0_0_10px_rgba(59,130,246,0.5)]" />
                      )}
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Section 3: Subject Selection */}
            <div className="animate-reveal">
              <div className="flex justify-between items-center mb-4 ml-1">
                <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Target Core Subjects</label>
                <span className={`text-[10px] font-black uppercase tracking-widest ${selectedSubjectIds.length === 3 ? 'text-emerald-400' : 'text-amber-500'}`}>
                  {selectedSubjectIds.length}/3 Selected
                </span>
              </div>
              <div className="grid grid-cols-1 gap-3">
                {currentStream.subjects.map(subject => {
                  const isSelected = selectedSubjectIds.includes(subject.id);
                  const isDisabled = !isSelected && selectedSubjectIds.length >= 3;

                  return (
                    <button
                      key={subject.id}
                      type="button"
                      disabled={isDisabled}
                      onClick={() => toggleSubject(subject.id)}
                      className={`text-left p-4 rounded-2xl border transition-all duration-300 flex items-center gap-4 ${
                        isSelected 
                          ? 'bg-emerald-600/10 border-emerald-500 shadow-[0_0_15px_rgba(16,185,129,0.1)]' 
                          : isDisabled 
                            ? 'opacity-40 grayscale cursor-not-allowed border-transparent'
                            : 'bg-slate-900/40 border-slate-800 hover:border-slate-700'
                      }`}
                    >
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-black text-white ${subject.color} shadow-lg shadow-black/20`}>
                        {subject.name[0]}
                      </div>
                      <div className="flex-1">
                        <span className={`text-sm font-bold block ${isSelected ? 'text-emerald-400' : 'text-slate-300'}`}>
                          {subject.name}
                        </span>
                        <span className="text-[9px] font-black uppercase tracking-tighter text-slate-500">
                          {subject.units.length} Units Found
                        </span>
                      </div>
                      {isSelected && (
                         <div className="w-5 h-5 rounded-full bg-emerald-500 flex items-center justify-center">
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 text-white" viewBox="0 0 20 20" fill="currentColor">
                              <path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" />
                            </svg>
                         </div>
                      )}
                    </button>
                  );
                })}
              </div>
              <p className="mt-4 text-[9px] text-slate-600 font-bold uppercase tracking-widest text-center italic">
                * Sri Lankan A/L streams require exactly 3 core subjects.
              </p>
            </div>
          </div>

          <div className="max-w-md mx-auto space-y-6">
            <div className="flex items-center justify-between px-1">
              <label className="flex items-center gap-3 cursor-pointer group">
                <div className="relative">
                  <input
                    type="checkbox"
                    checked={remember}
                    onChange={(e) => setRemember(e.target.checked)}
                    className="sr-only peer"
                  />
                  <div className="w-5 h-5 rounded-md border border-slate-700 bg-slate-900 peer-checked:bg-blue-600 peer-checked:border-blue-600 transition-all" />
                  <svg className="absolute top-1 left-1 w-3 h-3 text-white opacity-0 peer-checked:opacity-100 transition-opacity pointer-events-none" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
                  </svg>
                </div>
                <span className="text-xs font-bold text-slate-500 group-hover:text-slate-300">Sync data to browser</span>
              </label>
            </div>

            {error && (
              <div className="p-4 rounded-xl bg-red-500/10 border border-red-500/20 text-red-400 text-xs font-bold text-center animate-shake">
                {error}
              </div>
            )}

            <button
              type="submit"
              disabled={selectedSubjectIds.length !== 3}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-[0.2em] shadow-xl transition-all transform active:scale-[0.98] ${
                selectedSubjectIds.length === 3 
                  ? 'bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-blue-900/30' 
                  : 'bg-slate-900 text-slate-700 cursor-not-allowed border border-white/5'
              }`}
            >
              Initialize Strategy
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default LoginPage;

import React, { useMemo } from 'react';
import { Subject, Goal } from '../types';

interface ThreeARoadmapProps {
  subjects: Subject[];
  goals: Goal[];
}

const ThreeARoadmap: React.FC<ThreeARoadmapProps> = ({ subjects, goals }) => {
  const roadmapData = useMemo(() => {
    // Only track the top 3 subjects
    const topSubjects = subjects.slice(0, 3);
    const goalBoost = goals.length > 0 ? (goals.filter(g => g.completed).length / goals.length) * 10 : 0;

    return topSubjects.map(s => {
      const confidence = Math.min(100, s.progress + goalBoost);
      return {
        id: s.id,
        name: s.name,
        progress: s.progress,
        confidence,
        isReady: s.progress >= 75,
        color: s.color.replace('bg-', 'text-'),
        rawColor: s.color.replace('bg-', '')
      };
    });
  }, [subjects, goals]);

  return (
    <div className="w-full space-y-8 animate-reveal delay-300">
      <div className="flex items-center justify-between px-2">
        <div>
          <h3 className="text-[10px] font-black uppercase tracking-[0.4em] text-blue-500 mb-1">Strategic Outlook</h3>
          <h2 className="text-xl md:text-2xl font-black font-outfit text-white">The 3A Roadmap</h2>
        </div>
        <div className="text-right">
          <span className="text-[9px] font-black uppercase tracking-widest text-slate-500 block">Probability Index</span>
          <span className="text-sm font-black text-indigo-400">
            {roadmapData.length > 0 ? Math.round(roadmapData.reduce((acc, val) => acc + val.confidence, 0) / roadmapData.length) : 0}% High
          </span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {roadmapData.map((data) => (
          <div key={data.id} className="glass-card rounded-[2.5rem] p-8 border-white/5 relative overflow-hidden group">
            {/* Background Gradient Accent */}
            <div className={`absolute -right-10 -bottom-10 w-40 h-40 rounded-full blur-[80px] opacity-10 transition-all duration-700 group-hover:opacity-25 ${data.color.replace('text-', 'bg-')}`} />

            <div className="relative z-10 flex flex-col items-center text-center">
              {/* Grade Indicator with Glow and Fill */}
              <div className="relative w-32 h-32 mb-6 transform transition-transform group-hover:scale-110 duration-700">
                <svg className="w-full h-full transform -rotate-90">
                  {/* Track Circle */}
                  <circle
                    cx="64"
                    cy="64"
                    r="58"
                    stroke="currentColor"
                    strokeWidth="4"
                    fill="rgba(15, 23, 42, 0.4)"
                    className="text-slate-900"
                  />
                  {/* Fill Effect (Background Area) */}
                  <circle
                    cx="64"
                    cy="64"
                    r="58"
                    fill="currentColor"
                    className={`${data.isReady ? 'text-amber-500/10' : 'text-blue-500/5'} transition-all duration-[2s]`}
                    style={{ 
                      clipPath: `inset(${(100 - data.progress)}% 0 0 0)` // Simple vertical fill effect
                    }}
                  />
                  {/* Progress Glow Stroke */}
                  <circle
                    cx="64"
                    cy="64"
                    r="58"
                    stroke="currentColor"
                    strokeWidth="8"
                    strokeDasharray={2 * Math.PI * 58}
                    strokeDashoffset={2 * Math.PI * 58 - (data.progress / 100) * 2 * Math.PI * 58}
                    strokeLinecap="round"
                    fill="transparent"
                    className={`${data.isReady ? 'text-amber-400' : 'text-blue-500'} transition-all duration-[2s] ease-out`}
                    style={{ 
                      filter: `drop-shadow(0 0 12px ${data.isReady ? 'rgba(251,191,36,0.6)' : 'rgba(59,130,246,0.4)'})`
                    }}
                  />
                </svg>
                <div className="absolute inset-0 flex items-center justify-center">
                  <span className={`text-5xl font-black font-outfit transition-all duration-700 ${data.isReady ? 'text-amber-400 drop-shadow-[0_0_20px_rgba(251,191,36,0.8)] animate-pulse' : 'text-slate-800'}`}>
                    A
                  </span>
                </div>
              </div>

              <span className="text-xs font-black uppercase tracking-widest text-slate-400 mb-2">{data.name}</span>
              <div className="flex items-center gap-2 bg-black/30 px-4 py-1.5 rounded-full border border-white/5">
                <div className={`h-2 w-2 rounded-full ${data.isReady ? 'bg-amber-400 animate-ping' : 'bg-blue-600'}`} />
                <span className={`text-[10px] font-black uppercase tracking-widest ${data.isReady ? 'text-amber-400' : 'text-slate-500'}`}>
                  {data.isReady ? 'A-Grade Locked' : `${data.progress}% Mastered`}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Goal Multiplier Status */}
      <div className="bg-slate-900/40 p-6 rounded-[2rem] border border-white/5 flex items-center justify-between gap-8 backdrop-blur-md">
        <div className="flex items-center gap-5">
          <div className="w-12 h-12 rounded-2xl bg-indigo-600/10 flex items-center justify-center text-indigo-400 text-xl border border-indigo-500/20 shadow-lg">🎯</div>
          <div>
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-slate-500 block mb-0.5">Strategic Synergy</span>
            <span className="text-sm font-bold text-slate-300">
              {goals.filter(g => g.completed).length} / {goals.length} Strategic Targets Met
            </span>
          </div>
        </div>
        <div className="flex-1 max-w-sm bg-slate-950/80 rounded-full h-2 p-0.5 border border-white/5">
          <div 
            className="bg-gradient-to-r from-indigo-600 to-purple-500 h-full rounded-full transition-all duration-[1.5s] ease-out shadow-[0_0_15px_rgba(99,102,241,0.4)]" 
            style={{ width: `${goals.length > 0 ? (goals.filter(g => g.completed).length / goals.length) * 100 : 0}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default ThreeARoadmap;

import React, { useMemo } from 'react';
import { Subject, Goal } from '../types';

interface OverallStatsProps {
  subjects: Subject[];
  goals: Goal[];
}

const OverallStats: React.FC<OverallStatsProps> = ({ subjects, goals }) => {
  const stats = useMemo(() => {
    let totalUnits = 0;
    let completedUnits = 0;

    subjects.forEach(s => {
      totalUnits += s.units.length;
      completedUnits += s.units.filter(u => u.completed).length;
    });

    const masteryPercentage = totalUnits > 0 ? Math.round((completedUnits / totalUnits) * 100) : 0;
    const goalsCompleted = goals.filter(g => g.completed).length;

    // Calculate readiness level
    let readiness = "Foundation Stage";
    let readinessColor = "text-blue-400";
    let glowColor = "rgba(59, 130, 246, 0.4)";

    if (masteryPercentage > 30) { 
      readiness = "Operational"; 
      readinessColor = "text-indigo-400"; 
      glowColor = "rgba(99, 102, 241, 0.4)";
    }
    if (masteryPercentage > 60) { 
      readiness = "Advanced Mastery"; 
      readinessColor = "text-purple-400"; 
      glowColor = "rgba(168, 85, 247, 0.4)";
    }
    if (masteryPercentage > 85) { 
      readiness = "Strategic Readiness"; 
      readinessColor = "text-emerald-400"; 
      glowColor = "rgba(16, 185, 129, 0.4)";
    }

    return {
      masteryPercentage,
      totalUnits,
      completedUnits,
      goalsCompleted,
      readiness,
      readinessColor,
      glowColor
    };
  }, [subjects, goals]);

  return (
    <div className="glass-card rounded-[3.5rem] p-10 md:p-16 border-white/5 w-full animate-reveal overflow-hidden relative">
      {/* Dynamic Background Glow */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] h-[80%] bg-blue-600/5 blur-[120px] -z-10 rounded-full" />

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">

        {/* Visual Mastery Ring with Advanced Styling */}
        <div className="flex flex-col items-center justify-center relative group">
          <div className="absolute inset-0 bg-blue-500/5 blur-3xl rounded-full scale-75 group-hover:scale-100 transition-transform duration-1000" />

          <svg className="w-72 h-72 md:w-80 md:h-80 transform -rotate-90 relative z-10">
            {/* Outer Ring Shadow/Glow Background */}
            <circle
              cx="160"
              cy="160"
              r="140"
              stroke="rgba(255,255,255,0.02)"
              strokeWidth="20"
              fill="transparent"
            />
            {/* Track Circle */}
            <circle
              cx="160"
              cy="160"
              r="140"
              stroke="rgba(15, 23, 42, 0.8)"
              strokeWidth="12"
              fill="rgba(2, 6, 23, 0.6)"
            />
            {/* Dynamic Fill (Liquid Background) */}
            <circle
              cx="160"
              cy="160"
              r="140"
              fill="currentColor"
              className={`${stats.readinessColor.replace('text-', 'text-')}/10 transition-all duration-[2s]`}
              style={{ clipPath: `inset(${(100 - stats.masteryPercentage)}% 0 0 0)` }}
            />
            {/* Progress Circle with Heavy Neon Glow */}
            <circle
              cx="160"
              cy="160"
              r="140"
              stroke="currentColor"
              strokeWidth="14"
              strokeDasharray={2 * Math.PI * 140}
              strokeDashoffset={2 * Math.PI * 140 - (stats.masteryPercentage / 100) * 2 * Math.PI * 140}
              strokeLinecap="round"
              fill="transparent"
              className={`${stats.readinessColor} transition-all duration-[2.5s] ease-out`}
              style={{ filter: `drop-shadow(0 0 15px ${stats.glowColor})` }}
            />
          </svg>

          <div className="absolute flex flex-col items-center justify-center text-center z-20">
            <span className="text-7xl md:text-8xl font-black font-outfit text-white tracking-tighter leading-none mb-2">
              {stats.masteryPercentage}<span className="text-3xl text-blue-500 ml-1">%</span>
            </span>
            <span className="text-[11px] font-black uppercase tracking-[0.5em] text-slate-500">Readiness Score</span>
          </div>
        </div>

        {/* Breakdown Stats with Futuristic Cards */}
        <div className="space-y-10 relative z-10">
          <div>
            <h3 className="text-[10px] font-black uppercase tracking-[0.5em] text-blue-500 mb-3 ml-1">Live Candidate Status</h3>
            <p className={`text-4xl md:text-5xl font-black font-outfit tracking-tighter ${stats.readinessColor} drop-shadow-sm`}>
              {stats.readiness}
            </p>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-5">
            <div className="bg-slate-900/60 p-7 rounded-[2.5rem] border border-white/5 group hover:border-blue-500/30 transition-all">
              <span className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Academic Completion</span>
              <div className="flex items-end gap-2">
                <span className="text-3xl font-black text-white leading-none">{stats.completedUnits}</span>
                <span className="text-sm font-bold text-slate-600 mb-0.5">/ {stats.totalUnits} Units</span>
              </div>
              <div className="w-full bg-slate-950 h-1 rounded-full mt-4 overflow-hidden">
                <div className="bg-blue-500 h-full transition-all duration-[2s]" style={{ width: `${(stats.completedUnits / stats.totalUnits) * 100}%` }} />
              </div>
            </div>

            <div className="bg-slate-900/60 p-7 rounded-[2.5rem] border border-white/5 group hover:border-indigo-500/30 transition-all">
              <span className="block text-[10px] font-black uppercase tracking-widest text-slate-500 mb-2">Strategic Objectives</span>
